-- ========================================
-- 起步 > 项目介绍 (category_id=101)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(1, 101, '项目介绍', 'introduce', '', '全面了解 XYGo Admin 的技术栈、核心特色与设计理念',
E'# 关于 XYGo Admin\n\nXYGo Admin 是一款基于 **GoFrame + Vue3 + Element Plus + Tailwind CSS** 的企业级中后台管理系统。项目采用前后端分离架构，融合现代化设计理念与工程化实践，致力于为开发者提供高效、优雅的开发基础。\n\n## 核心特色\n\n### 🎨 Clay 拟态设计\n\n项目独创的 Clay（黏土拟态）设计体系，通过科学的阴影层次和柔和的光影效果，打造出极具质感的 UI 界面。告别传统管理系统的视觉疲劳，让每一次操作都赏心悦目。\n\n### ⚡ 全栈代码生成\n\n内置强大的 CRUD 代码生成器，支持：\n- 可视化建表设计器\n- 字段配置与类型推断\n- 一键生成 Go 后端（API + Controller + Logic）+ Vue 前端（列表页 + 弹窗 + 搜索栏）\n- 自动注册路由、菜单与权限\n\n### 🔐 三级权限体系\n\n- **角色权限（RBAC）**：基于角色的菜单与接口访问控制\n- **按钮级权限**：精确到每个操作按钮的显隐控制\n- **字段级权限**：控制数据字段的可见性与可编辑性\n\n### 💬 即时通讯\n\n基于 WebSocket 的实时聊天系统，支持单聊、群聊、在线状态检测、消息已读回执。\n\n### 📊 系统监控\n\n内置服务器监控、性能分析（pprof）、慢接口检测、操作日志审计等运维工具。\n\n## 技术栈\n\n### 后端\n\n| 技术 | 说明 |\n|------|------|\n| Go 1.24 | 编程语言 |\n| GoFrame v2 | Web 框架 |\n| MySQL / PostgreSQL | 数据库（双驱动支持） |\n| Redis | 缓存 |\n| JWT | 身份认证 |\n| WebSocket | 即时通讯 |\n| 阿里云 OSS / 七牛 / 腾讯 COS | 对象存储 |\n\n### 前端\n\n| 技术 | 说明 |\n|------|------|\n| Vue 3.5 | 渐进式框架 |\n| TypeScript 5.6 | 类型安全 |\n| Vite 7 | 构建工具 |\n| Element Plus | UI 组件库 |\n| Tailwind CSS 4 | 原子化 CSS |\n| Pinia 3 | 状态管理 |\n| ECharts 6 | 数据可视化 |\n| vue-i18n | 国际化 |\n\n## 浏览器兼容性\n\n支持 Chrome、Edge、Firefox、Safari、Opera 等现代浏览器（ES2015+）。\n\n## 开源协议\n\n本项目基于 **Apache 2.0** 协议开源，无需授权即可商业使用。',
'XYGo Admin', 0, 100, 1, 1, '["介绍","技术栈"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 起步 > 快速上手 (category_id=102)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(2, 102, '快速上手', 'quick-start', '', '从零开始搭建开发环境，5 分钟启动项目',
E'# 快速上手\n\n## 环境准备\n\n在开始之前，请确保你的开发环境已安装以下工具：\n\n| 工具 | 版本要求 | 说明 |\n|------|---------|------|\n| Go | >= 1.22 | 后端运行环境 |\n| Node.js | >= 18 | 前端运行环境 |\n| pnpm | >= 8 | 包管理器（推荐） |\n| MySQL 或 PostgreSQL | MySQL >= 5.7 / PG >= 12 | 数据库 |\n| Redis | >= 6 | 缓存服务 |\n| Git | 最新版 | 版本控制 |\n\n## 获取代码\n\n```bash\n# 克隆仓库\ngit clone https://github.com/your-org/xygoadmin.git\ncd xygoadmin\n```\n\n## 数据库配置\n\n### 1. 创建数据库\n\n```sql\n-- MySQL\nCREATE DATABASE xygoadmin DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci;\n\n-- PostgreSQL\nCREATE DATABASE xygoadmin WITH ENCODING ''UTF8'';\n```\n\n### 2. 导入建表脚本\n\n根据你使用的数据库类型，执行对应的 SQL 文件：\n\n```bash\n# MySQL\nmysql -u root -p xygoadmin < mysql_install.sql\n\n# PostgreSQL\npsql -U postgres -d xygoadmin -f pgsql_install.sql\n```\n\n### 3. 修改配置文件\n\n编辑 `server/manifest/config/config.yaml`，配置数据库连接信息：\n\n```yaml\ndatabase:\n  default:\n    link: \"pgsql:postgres:123456@tcp(127.0.0.1:5432)/xygoadmin\"\n    # 或 MySQL:\n    # link: \"mysql:root:123456@tcp(127.0.0.1:3306)/xygoadmin\"\n```\n\n## 启动后端\n\n```bash\ncd server\n\n# 安装 GoFrame CLI（首次）\ngo install github.com/gogf/gf/cmd/gf/v2@latest\n\n# 启动服务\ngf run main.go\n```\n\n服务默认运行在 `http://localhost:8000`。\n\n## 启动前端\n\n```bash\ncd web\n\n# 安装依赖\npnpm install\n\n# 启动开发服务器\npnpm dev\n```\n\n浏览器会自动打开 `http://localhost:5173`。\n\n## 默认账号\n\n| 角色 | 账号 | 密码 |\n|------|------|------|\n| 超级管理员 | admin | 123456 |\n\n## 常用命令\n\n```bash\n# 生成 DAO 代码\ngf gen dao\n\n# 生成 Service 接口\ngf gen service\n\n# 前端构建\npnpm build\n\n# 前端代码检查\npnpm lint\n```\n\n> **提示**：如果遇到问题，请查看 [常见问题](/docs/faq) 章节。',
'XYGo Admin', 0, 90, 1, 0, '["安装","入门"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 起步 > 开发者必读 (category_id=103)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(3, 103, '开发者必读', 'must-read', '', '了解项目架构、开发规范和注意事项，避免踩坑',
E'# 开发者必读\n\n在开始开发之前，请务必阅读本文档，了解项目的核心架构和开发规范。\n\n## 项目架构\n\nXYGo Admin 采用经典的前后端分离架构：\n\n```\nxygoadmin/\n├── server/          # Go 后端（GoFrame）\n│   ├── api/         # API 接口定义（请求/响应结构体）\n│   ├── internal/\n│   │   ├── cmd/         # 启动命令\n│   │   ├── controller/  # 控制器（路由处理）\n│   │   ├── logic/       # 业务逻辑（核心实现）\n│   │   ├── service/     # 服务接口（自动生成）\n│   │   ├── model/       # 数据模型\n│   │   │   ├── entity/  # 数据库实体（自动生成）\n│   │   │   ├── do/      # 数据操作对象（自动生成）\n│   │   │   └── input/   # 输入/输出结构体\n│   │   ├── dao/         # 数据访问层（自动生成）\n│   │   └── middleware/  # 中间件\n│   └── manifest/\n│       └── config/      # 配置文件\n└── web/             # Vue3 前端\n    └── src/\n        ├── api/         # API 请求封装\n        ├── components/  # 公共组件\n        ├── views/       # 页面视图\n        ├── router/      # 路由配置\n        ├── store/       # 状态管理\n        └── utils/       # 工具函数\n```\n\n## 后端分层架构\n\n请求处理遵循以下流程：\n\n```\nHTTP Request\n  → Middleware（鉴权、日志、响应包装）\n    → Controller（参数校验、调用 Service）\n      → Service（接口定义）\n        → Logic（业务逻辑实现）\n          → DAO（数据库操作）\n            → Database\n```\n\n### 关键规则\n\n1. **Controller 层**：只做参数接收和结果返回，不写业务逻辑\n2. **Logic 层**：所有业务逻辑都在这里实现\n3. **Service 层**：由 `gf gen service` 自动生成，不要手动修改\n4. **DAO 层**：`dao/internal/` 下的文件由 CLI 自动生成，不要修改；扩展方法写在 `dao/` 外层\n5. **Entity/DO**：由 `gf gen dao` 自动生成，不要手动修改\n\n## 前端开发规范\n\n### 组件命名\n\n- 公共组件以 `Art` 前缀命名：`ArtTable`、`ArtSearchBar`、`ArtSvgIcon`\n- 页面组件使用 PascalCase：`UserList.vue`、`DocDialog.vue`\n\n### 图标使用\n\n项目统一使用 **Remix Icon** 图标库，通过 `ArtSvgIcon` 组件引用：\n\n```vue\n<ArtSvgIcon icon=\"ri:home-line\" class=\"text-xl\" />\n```\n\n可在 [Remix Icon 官网](https://remixicon.com/) 搜索图标。\n\n### 网络请求\n\n项目封装了三套请求实例，按场景使用：\n\n| 实例 | 前缀 | Token | 用途 |\n|------|------|-------|------|\n| `adminRequest` | `/admin` | Bearer Token | 后台管理接口 |\n| `memberRequest` | `/member` | Xy-User-Token | 前台会员接口 |\n| `siteRequest` | `/site` | 无 | 前台公共接口 |\n\n### 状态管理\n\n使用 Pinia 3 + 持久化插件，Store 文件放在 `src/store/modules/` 下。\n\n## 数据库规范\n\n- 表名统一使用 `xy_` 前缀\n- 字段命名使用 snake_case\n- 时间字段统一使用 UNIX 时间戳（bigint）\n- 软删除字段：`deleted_at`（0 表示未删除）\n- 必备字段：`id`、`created_at`、`updated_at`\n\n## Git 提交规范\n\n项目使用 commitizen + cz-git，提交格式：\n\n```\nfeat: 新增用户管理模块\nfix: 修复登录页验证码不显示\ndocs: 更新部署文档\nstyle: 调整表格样式\nrefactor: 重构权限校验逻辑\n```',
'XYGo Admin', 0, 80, 1, 0, '["架构","规范"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 起步 > CRUD代码生成 (category_id=104)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(4, 104, 'CRUD 代码生成', 'crud-gen', '', '使用内置代码生成器快速创建完整的增删改查功能',
E'# CRUD 代码生成\n\n代码生成器是 XYGo Admin 的核心功能之一，可以从数据库表一键生成完整的前后端 CRUD 代码。\n\n## 功能概览\n\n- 📋 **表选择**：从数据库中选择已有表\n- 🎨 **建表设计器**：可视化设计新表结构\n- ⚙️ **字段配置**：配置每个字段的展示方式、验证规则\n- 👁️ **代码预览**：生成前预览所有代码文件\n- 🚀 **一键生成**：自动生成并注册到项目中\n\n## 使用步骤\n\n### 第一步：进入代码生成器\n\n在后台管理系统中，导航到 **开发工具 → 代码生成**。\n\n### 第二步：选择或创建表\n\n**方式一：选择已有表**\n\n点击「选择数据表」，从下拉列表中选择要生成代码的表。系统会自动读取表结构和字段信息。\n\n**方式二：可视化建表**\n\n点击「新建表」，打开建表设计器：\n- 设置表名、表注释\n- 添加字段，配置字段名、类型、长度、默认值、注释\n- 设置索引\n- 点击「创建」，系统会自动执行 DDL 并同步字段\n\n### 第三步：配置字段\n\n系统会智能推断每个字段的展示类型（designType），你也可以手动调整：\n\n| 展示类型 | 说明 | 适用场景 |\n|---------|------|----------|\n| input | 文本输入框 | 普通文本字段 |\n| textarea | 多行文本 | 备注、描述 |\n| number | 数字输入 | 数量、金额 |\n| select | 下拉选择 | 状态、类型 |\n| switch | 开关 | 是/否字段 |\n| date | 日期选择 | 日期字段 |\n| timestamp | 时间戳 | created_at 等 |\n| editor | 富文本编辑器 | 内容字段 |\n| image | 图片上传 | 头像、封面 |\n| remoteSelect | 远程搜索选择 | 关联表字段 |\n\n### 第四步：预览与生成\n\n点击「预览」可以查看将要生成的所有文件：\n\n**后端文件：**\n- `api/admin/xxx.go` — API 接口定义\n- `controller/admin/xxx.go` — 控制器\n- `model/input/adminin/xxx.go` — 输入/输出结构体\n- `logic/xxx/xxx.go` — 业务逻辑\n\n**前端文件：**\n- `api/backend/xxx.ts` — API 请求\n- `views/backend/xxx/index.vue` — 列表页\n- `views/backend/xxx/modules/xxx-dialog.vue` — 编辑弹窗\n\n**其他：**\n- 菜单 SQL — 自动插入菜单和权限数据\n- `logic.go` — 自动注册 Logic 导入\n\n确认无误后点击「生成」，代码会自动写入项目目录。\n\n### 第五步：重启服务\n\n```bash\n# 生成 DAO\ngf gen dao\n\n# 生成 Service\ngf gen service\n\n# 重启后端\ngf run main.go\n```\n\n前端代码会在「发布前端」操作后写入 `web/src/` 目录，热更新会自动生效。\n\n## 高级功能\n\n### 树表支持\n\n如果表中包含 `pid` 字段，生成器会自动识别为树形结构，生成树表相关代码。\n\n### 字段同步\n\n当你修改了数据库表结构后，可以使用「同步字段」功能，系统会对比差异并提示 ADD / DROP / MODIFY 操作。\n\n### 关联表\n\n支持配置关联表查询，在列表和表单中展示关联数据。',
'XYGo Admin', 0, 70, 1, 0, '["代码生成","CRUD"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 起步 > 常见问题 (category_id=105)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(5, 105, '常见问题', 'faq', '', '开发过程中常见问题的解答汇总',
E'# 常见问题\n\n## 启动相关\n\n### Q: 后端启动报 \"database connection failed\"\n\n请检查：\n1. 数据库服务是否已启动\n2. `config.yaml` 中的数据库连接信息是否正确\n3. 数据库用户是否有访问权限\n4. 如果使用 PostgreSQL，确认连接字符串格式为 `pgsql:user:pass@tcp(host:port)/dbname`\n\n### Q: 前端启动报 \"port 5173 is already in use\"\n\n端口被占用，可以修改 `vite.config.ts` 中的端口，或关闭占用端口的进程：\n\n```bash\n# Windows\nnetstat -ano | findstr :5173\ntaskkill /PID <pid> /F\n\n# Linux/Mac\nlsof -i :5173\nkill -9 <pid>\n```\n\n### Q: `gf gen dao` 报错\n\n确认 `server/hack/config.yaml` 中的数据库连接配置正确，且 GoFrame CLI 版本与项目匹配：\n\n```bash\ngf version\n# 建议 >= v2.7\n```\n\n## 开发相关\n\n### Q: 新增的接口 404\n\n检查以下几点：\n1. API 定义文件中的 `g.Meta` tag 路径是否正确\n2. Controller 是否已在 `cmd.go` 中注册到对应路由组\n3. 后端是否已重启（Go 不支持热更新）\n\n### Q: 前端页面空白，控制台无报错\n\n可能原因：\n1. 路由未正确配置，检查菜单数据中的 `component` 路径\n2. 动态路由未加载，确认用户角色有该菜单权限\n3. 组件文件路径大小写不匹配（Linux 区分大小写）\n\n### Q: 上传文件失败\n\n1. 检查 `sys_config` 表中 `oss` 分组的配置\n2. 确认上传目录有写入权限\n3. 检查文件大小是否超过限制\n4. 如使用云存储，确认 AccessKey 配置正确\n\n## 部署相关\n\n### Q: 生产环境接口跨域\n\n在 Nginx 中配置反向代理，将 API 请求转发到后端服务：\n\n```nginx\nlocation /admin/ {\n    proxy_pass http://127.0.0.1:8000;\n    proxy_set_header Host $host;\n    proxy_set_header X-Real-IP $remote_addr;\n}\n```\n\n### Q: WebSocket 连接失败\n\nNginx 需要额外配置 WebSocket 支持：\n\n```nginx\nlocation /socket/ {\n    proxy_pass http://127.0.0.1:8000;\n    proxy_http_version 1.1;\n    proxy_set_header Upgrade $http_upgrade;\n    proxy_set_header Connection \"upgrade\";\n}\n```\n\n### Q: 前端打包后页面刷新 404\n\n项目默认使用 Hash 路由模式（URL 带 `#`），不会出现此问题。如果切换为 History 模式，需要在 Nginx 中配置：\n\n```nginx\nlocation / {\n    try_files $uri $uri/ /index.html;\n}\n```',
'XYGo Admin', 0, 60, 1, 0, '["FAQ","问题"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 进阶 > 目录结构 (category_id=201)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(6, 201, '目录结构', 'structure', '', '详细了解 server 和 web 的完整目录结构',
E'# 目录结构\n\n## 后端目录 server/\n\n```\nserver/\n├── api/                    # API 接口定义\n│   ├── admin/              # 后台管理接口（请求/响应结构体 + g.Meta 路由声明）\n│   ├── member/             # 会员端接口\n│   ├── site/               # 前台公共接口\n│   └── system/             # 系统接口（验证码、健康检查）\n├── internal/               # 内部模块（不可外部引用）\n│   ├── cmd/                # 启动命令（HTTP Server 初始化、路由注册、中间件挂载）\n│   ├── controller/         # 控制器层\n│   │   ├── admin/          # 后台控制器（20+ 文件）\n│   │   ├── member/         # 会员控制器\n│   │   ├── site/           # 前台控制器\n│   │   └── system/         # 系统控制器\n│   ├── logic/              # 业务逻辑层（核心代码）\n│   │   ├── admin/          # 管理员管理\n│   │   ├── chat/           # 即时聊天\n│   │   ├── cmsdoc/         # CMS 文档\n│   │   ├── cron/           # 定时任务\n│   │   ├── dept/           # 部门管理\n│   │   ├── gencodes/       # 代码生成器\n│   │   ├── log/            # 日志管理\n│   │   ├── member/         # 会员（认证/签到/通知/菜单/分组）\n│   │   ├── monitor/        # 系统监控\n│   │   ├── notice/         # 通知公告\n│   │   ├── post/           # 岗位管理\n│   │   ├── sysconfig/      # 系统配置\n│   │   ├── user/           # 后台用户/登录\n│   │   ├── upload.go       # 文件上传\n│   │   └── logic.go        # 统一注册入口\n│   ├── service/            # 服务接口层（gf gen service 自动生成）\n│   ├── model/              # 数据模型\n│   │   ├── entity/         # 数据库实体（gf gen dao 自动生成）\n│   │   ├── do/             # 数据操作对象（自动生成）\n│   │   └── input/          # 输入/输出结构体\n│   │       ├── adminin/    # 后台输入（25 个文件）\n│   │       ├── memberin/   # 会员输入\n│   │       └── form/       # 通用分页结构\n│   ├── dao/                # 数据访问层\n│   │   ├── internal/       # 内层 DAO（自动生成，勿修改）\n│   │   └── *.go            # 外层 DAO（可扩展自定义方法）\n│   ├── middleware/         # 中间件\n│   │   ├── auth.go         # 后台 JWT 鉴权\n│   │   ├── member_auth.go  # 会员鉴权\n│   │   ├── ws_auth.go      # WebSocket 鉴权\n│   │   ├── cors.go         # 跨域处理\n│   │   ├── response.go     # 统一响应包装\n│   │   ├── operation_log.go # 操作日志\n│   │   └── performance.go  # 慢接口监控\n│   ├── library/            # 基础库\n│   │   ├── token/          # JWT 令牌\n│   │   ├── cache/          # 缓存\n│   │   ├── cron/           # 定时任务调度引擎\n│   │   ├── queue/          # 消息队列（Redis/Disk 双驱动）\n│   │   ├── monitor/        # 性能监控\n│   │   ├── storager/       # 存储驱动（本地/OSS/COS/七牛）\n│   │   ├── dbdialect/      # 数据库方言（MySQL/PG 适配）\n│   │   └── security/       # 安全（脱敏/登录保护）\n│   ├── crons/              # 定时任务注册\n│   ├── queues/             # 消息队列消费者注册\n│   ├── field/              # 资源注册\n│   └── websocket/          # WebSocket 基础设施\n├── manifest/\n│   └── config/             # 配置文件\n├── resource/\n│   └── sql/                # SQL 脚本\n├── hack/\n│   └── config.yaml         # GoFrame CLI 配置\n├── go.mod\n└── main.go                 # 入口文件\n```\n\n## 前端目录 web/\n\n```\nweb/\n├── src/\n│   ├── api/                # API 请求\n│   │   ├── backend/        # 后台 API（auth/system/common/cms）\n│   │   └── frontend/       # 前台 API（member/doc）\n│   ├── components/         # 公共组件\n│   │   ├── core/           # 核心组件\n│   │   │   ├── base/       # 基础（Logo）\n│   │   │   ├── charts/     # 图表（9 种 ECharts 组件）\n│   │   │   ├── forms/      # 表单（16 个组件）\n│   │   │   ├── tables/     # 表格（ArtTable/ArtTableHeader）\n│   │   │   ├── layouts/    # 布局（20+ 组件）\n│   │   │   ├── media/      # 媒体（视频播放/图片裁剪）\n│   │   │   └── others/     # 其他（水印/右键菜单）\n│   │   └── business/       # 业务组件\n│   ├── views/              # 页面视图\n│   │   ├── backend/        # 后台页面（12 个模块）\n│   │   └── frontend/       # 前台页面（首页/文档/社区/案例/会员）\n│   ├── router/             # 路由\n│   │   ├── routes/         # 静态路由 + 动态路由\n│   │   ├── modules/        # 后台路由模块\n│   │   ├── guards/         # 路由守卫\n│   │   └── core/           # 路由核心工具\n│   ├── store/              # Pinia 状态管理\n│   ├── locales/            # 国际化（zh/en）\n│   ├── directives/         # 自定义指令（v-auth/v-roles/v-ripple/v-highlight）\n│   ├── utils/              # 工具函数\n│   │   ├── http/           # Axios 封装\n│   │   ├── socket/         # WebSocket 客户端\n│   │   ├── storage/        # 本地存储\n│   │   └── ...             # 导航/UI/表单/表格/系统\n│   ├── types/              # TypeScript 类型定义\n│   └── styles/             # 全局样式\n├── vite.config.ts          # Vite 配置\n├── package.json\n└── tsconfig.json\n```',
'XYGo Admin', 0, 100, 1, 0, '["目录","结构"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 进阶 > 后台交互流程 (category_id=202)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(7, 202, '后台交互流程', 'interaction', '', '前后端请求流程、JWT 认证机制与接口规范',
E'# 后台交互流程\n\n## 请求流程\n\n前端发起请求到后端响应的完整链路：\n\n```\n前端 API 调用\n  → Axios 拦截器（自动注入 Token）\n    → HTTP 请求\n      → Nginx 反向代理\n        → GoFrame HTTP Server\n          → CORS 中间件\n            → 慢接口监控中间件\n              → 响应包装中间件\n                → 鉴权中间件（JWT 校验）\n                  → 操作日志中间件\n                    → Controller\n                      → Service → Logic → DAO → DB\n```\n\n## JWT 认证\n\n### 后台管理员认证\n\n- Token 类型：Bearer Token\n- Header：`Authorization: Bearer <token>`\n- 有效期：配置文件中设置\n- 刷新机制：Token 过期后返回 code=61，前端自动跳转登录页\n\n### 前台会员认证\n\n- Token 类型：自定义 Header\n- Header：`Xy-User-Token: <token>`\n- 独立于后台管理员 Token，互不影响\n\n### 被踢下线\n\n当管理员在其他设备登录时，当前设备会收到 code=10010，前端弹窗提示并跳转登录页。\n\n## 统一响应格式\n\n所有接口返回统一的 JSON 结构：\n\n```json\n{\n  \"code\": 0,\n  \"message\": \"success\",\n  \"data\": {},\n  \"traceId\": \"abc123\"\n}\n```\n\n| 字段 | 说明 |\n|------|------|\n| code | 业务状态码，0=成功，-1=失败，61=未授权，10010=被踢下线 |\n| message | 提示信息 |\n| data | 业务数据 |\n| traceId | 请求追踪 ID |\n\n## 前端请求封装\n\n项目提供三套请求实例：\n\n```typescript\nimport { adminRequest } from ''@/utils/http''\nimport { memberRequest } from ''@/utils/http''\nimport { siteRequest } from ''@/utils/http''\n\n// 后台管理接口\nconst res = await adminRequest.get({ url: ''/user/list'' })\n\n// 会员接口\nconst res = await memberRequest.post({ url: ''/auth/login'', params: data })\n\n// 公共接口（无需登录）\nconst res = await siteRequest.get({ url: ''/doc/list'' })\n```\n\n### 请求拦截器\n\n- 根据 URL 前缀自动区分后台 Token / 会员 Token\n- 自动从 Store 中读取并注入 Token\n\n### 响应拦截器\n\n- code=0：返回 data 字段\n- code=61：清除 Token，跳转登录页（3 秒防抖）\n- code=10010：弹窗提示被踢下线\n- 其他：ElMessage 提示错误信息\n\n## API 定义规范（后端）\n\n使用 GoFrame 的声明式路由，在 `api/` 目录定义请求和响应结构体：\n\n```go\ntype UserListReq struct {\n    g.Meta   `path:\"/user/list\" method:\"get\" tags:\"用户管理\" summary:\"用户列表\"`\n    Page     int    `json:\"page\" d:\"1\"`\n    PageSize int    `json:\"pageSize\" d:\"20\"`\n    Username string `json:\"username\"`\n}\n\ntype UserListRes struct {\n    List  []entity.AdminUser `json:\"list\"`\n    Total int                `json:\"total\"`\n}\n```',
'XYGo Admin', 0, 90, 1, 0, '["交互","JWT"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 进阶 > 菜单与路由 (category_id=203)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(8, 203, '菜单与路由', 'menu-route', '', '动态菜单加载、路由权限控制与前后台双路由体系',
E'# 菜单与路由\n\n## 双路由体系\n\nXYGo Admin 采用前台 + 后台双路由体系，完全隔离：\n\n| 路由 | 前缀 | 模式 | 说明 |\n|------|------|------|------|\n| 前台门户 | `/` | 静态注册 | 首页、文档、社区、会员中心 |\n| 后台管理 | `/admin` | 动态加载 | 根据角色权限动态注册 |\n\n## 前台路由\n\n前台路由在 `router/frontend/` 中静态定义，使用独立的 `FrontendLayout` 布局：\n\n```typescript\n// router/frontend/index.ts\nconst frontendRoutes = [\n  { path: ''/'', component: FrontendLayout, children: [\n    { path: '''', name: ''Home'', component: () => import(''@/views/frontend/index/index.vue'') },\n    { path: ''docs'', name: ''Docs'', component: () => import(''@/views/frontend/docs/index.vue'') },\n    { path: ''community'', name: ''Community'', component: () => import(''@/views/frontend/community/index.vue'') },\n    { path: ''cases'', name: ''Cases'', component: () => import(''@/views/frontend/cases/index.vue'') },\n  ]}\n]\n```\n\n## 后台动态路由\n\n后台路由在用户首次访问 `/admin/*` 时从后端获取菜单数据并动态注册。\n\n### 加载流程\n\n```\n用户访问 /admin/dashboard\n  → beforeEach 路由守卫\n    → 检查是否已登录（Token 存在）\n      → 检查动态路由是否已注册\n        → 未注册：调用后端接口获取菜单列表\n          → RouteTransformer 转换为 Vue Router 路由\n            → RouteRegistry 动态注册路由\n              → 跳转目标页面\n```\n\n### 菜单数据结构\n\n后端返回的菜单数据：\n\n```json\n{\n  \"id\": 1,\n  \"pid\": 0,\n  \"title\": \"系统管理\",\n  \"icon\": \"ri:settings-3-line\",\n  \"path\": \"/system\",\n  \"component\": \"LAYOUT\",\n  \"type\": 1,\n  \"children\": [\n    {\n      \"id\": 2,\n      \"pid\": 1,\n      \"title\": \"用户管理\",\n      \"path\": \"user\",\n      \"component\": \"/system/user/index\",\n      \"authList\": [\"add\", \"edit\", \"delete\"]\n    }\n  ]\n}\n```\n\n### 路由核心工具\n\n| 工具类 | 职责 |\n|--------|------|\n| `RouteRegistry` | 动态路由注册与卸载 |\n| `ComponentLoader` | 组件懒加载 |\n| `RouteValidator` | 路由合法性验证 |\n| `RouteTransformer` | 菜单数据 → Vue 路由转换 |\n| `MenuProcessor` | 菜单数据处理 |\n| `RoutePermissionValidator` | 路由权限校验 |\n| `IframeRouteManager` | Iframe 页面路由管理 |\n\n## 路由守卫\n\n### beforeEach（前置守卫）\n\n1. 白名单页面直接放行（登录、注册、前台页面）\n2. 未登录跳转登录页\n3. 已登录但未加载动态路由 → 加载菜单并注册\n4. 权限校验\n\n### afterEach（后置守卫）\n\n- 更新页面标题\n- 关闭加载进度条',
'XYGo Admin', 0, 80, 1, 0, '["菜单","路由","权限"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 进阶 > 权限管理 (category_id=204)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(9, 204, '权限管理', 'permission', '', 'RBAC 角色权限 + 按钮级权限 + 字段级权限的完整体系',
E'# 权限管理\n\nXYGo Admin 实现了三级权限控制体系，从粗到细覆盖所有场景。\n\n## 一、角色权限（RBAC）\n\n基于角色的访问控制，管理员通过角色关联菜单权限。\n\n### 角色类型\n\n| 角色标识 | 说明 |\n|---------|------|\n| R_SUPER | 超级管理员，拥有所有权限，不受权限校验限制 |\n| R_ADMIN | 普通管理员，权限由分配的菜单决定 |\n| 自定义 | 可创建任意角色并分配菜单权限 |\n\n### 权限分配流程\n\n1. 创建角色\n2. 为角色分配菜单（勾选菜单树）\n3. 将角色分配给用户\n4. 用户登录后，后端返回该角色可访问的菜单列表\n5. 前端根据菜单列表动态注册路由\n\n## 二、按钮级权限\n\n精确控制页面中每个操作按钮的显隐。\n\n### 后端配置\n\n在菜单管理中，为页面菜单添加「按钮」类型的子节点：\n\n- 菜单类型：按钮\n- 权限标识：如 `add`、`edit`、`delete`、`export`\n\n### 前端使用\n\n通过 `v-auth` 指令控制按钮显隐：\n\n```vue\n<template>\n  <!-- 只有拥有 add 权限的角色才能看到此按钮 -->\n  <ElButton v-auth=\"''add''\" type=\"primary\">新增</ElButton>\n  \n  <!-- 多个权限（满足其一即可） -->\n  <ElButton v-auth=\"[''edit'', ''update'']\" type=\"primary\">编辑</ElButton>\n</template>\n```\n\n`v-auth` 指令的工作原理：\n1. 从当前路由的 `meta.authList` 中获取权限列表\n2. 判断用户是否拥有指定权限\n3. 无权限则从 DOM 中移除该元素\n\n### 角色指令\n\n通过 `v-roles` 指令按角色控制：\n\n```vue\n<template>\n  <!-- 只有超级管理员可见 -->\n  <div v-roles=\"''R_SUPER''\">超级管理员专属内容</div>\n</template>\n```\n\n## 三、字段级权限\n\n控制数据字段的可见性和可编辑性，适用于敏感数据保护。\n\n### 配置方式\n\n在后台「字段权限」管理中：\n1. 选择目标模块（如用户管理）\n2. 配置每个字段对不同角色的权限：\n   - **可见**：该角色可以看到此字段\n   - **可编辑**：该角色可以修改此字段\n   - **隐藏**：该角色看不到此字段\n\n### 后端实现\n\n通过 `admin_field_perm` 表存储字段权限配置，在查询和更新时自动过滤字段。\n\n## 权限校验流程\n\n```\n请求到达\n  → AdminAuth 中间件\n    → 解析 JWT Token\n      → 获取用户角色\n        → R_SUPER？直接放行\n        → 检查请求路径是否在角色菜单权限中\n          → 有权限：继续处理\n          → 无权限：返回 403\n```',
'XYGo Admin', 0, 70, 1, 0, '["权限","RBAC"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 进阶 > 国际化 (category_id=205)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(10, 205, '国际化', 'i18n', '', 'vue-i18n 多语言配置与使用指南',
E'# 国际化\n\nXYGo Admin 基于 `vue-i18n` 实现多语言支持，目前内置简体中文和英文。\n\n## 语言文件\n\n语言包位于 `web/src/locales/` 目录：\n\n```\nlocales/\n├── index.ts          # i18n 实例创建与配置\n└── langs/\n    ├── zh.json       # 简体中文\n    └── en.json       # English\n```\n\n## 配置说明\n\n```typescript\n// locales/index.ts\nimport { createI18n } from ''vue-i18n''\nimport zh from ''./langs/zh.json''\nimport en from ''./langs/en.json''\n\nconst i18n = createI18n({\n  locale: ''zh'',           // 默认语言\n  fallbackLocale: ''en'',   // 回退语言\n  messages: { zh, en }\n})\n```\n\n语言偏好会自动保存到 localStorage，下次访问时恢复。\n\n## 使用方式\n\n### 模板中使用\n\n```vue\n<template>\n  <h1>{{ $t(''dashboard.title'') }}</h1>\n  <p>{{ $t(''common.welcome'', { name: username }) }}</p>\n</template>\n```\n\n### 脚本中使用\n\n```typescript\nimport { useI18n } from ''vue-i18n''\n\nconst { t } = useI18n()\nconsole.log(t(''common.success''))\n```\n\n## 语言包格式\n\n```json\n{\n  \"common\": {\n    \"success\": \"操作成功\",\n    \"failed\": \"操作失败\",\n    \"confirm\": \"确定\",\n    \"cancel\": \"取消\",\n    \"welcome\": \"欢迎，{name}\"\n  },\n  \"dashboard\": {\n    \"title\": \"控制台\"\n  }\n}\n```\n\n## 切换语言\n\n前台布局中提供了语言切换按钮，点击即可切换。切换后会：\n1. 更新 i18n locale\n2. 保存到 localStorage\n3. 更新 Element Plus 的语言包\n\n## 添加新语言\n\n1. 在 `locales/langs/` 下新建语言文件，如 `ja.json`\n2. 在 `locales/index.ts` 中导入并注册\n3. 在语言切换组件中添加选项',
'XYGo Admin', 0, 60, 1, 0, '["国际化","i18n"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 进阶 > 构建与部署 (category_id=206)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(11, 206, '构建与部署', 'deploy', '', '生产环境构建、Nginx 配置与 Docker 部署指南',
E'# 构建与部署\n\n## 前端构建\n\n```bash\ncd web\n\n# 构建生产版本\npnpm build\n```\n\n构建产物输出到 `web/dist/` 目录。构建配置：\n- Target: ES2015\n- 压缩：Terser（自动移除 console 和 debugger）\n- Gzip：vite-plugin-compression 自动生成 .gz 文件\n- Chunk 警告阈值：2000KB\n\n## 后端构建\n\n```bash\ncd server\n\n# 编译为可执行文件\ngo build -o xygoadmin main.go\n\n# 或使用 GoFrame CLI\ngf build\n```\n\n## Nginx 配置\n\n```nginx\nserver {\n    listen 80;\n    server_name your-domain.com;\n\n    # 前端静态文件\n    location / {\n        root /var/www/xygoadmin/dist;\n        index index.html;\n        try_files $uri $uri/ /index.html;\n    }\n\n    # 后台 API 代理\n    location /admin/ {\n        proxy_pass http://127.0.0.1:8000;\n        proxy_set_header Host $host;\n        proxy_set_header X-Real-IP $remote_addr;\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n        proxy_set_header X-Forwarded-Proto $scheme;\n    }\n\n    # 会员 API 代理\n    location /member/ {\n        proxy_pass http://127.0.0.1:8000;\n        proxy_set_header Host $host;\n        proxy_set_header X-Real-IP $remote_addr;\n    }\n\n    # 前台公共 API\n    location /site/ {\n        proxy_pass http://127.0.0.1:8000;\n        proxy_set_header Host $host;\n        proxy_set_header X-Real-IP $remote_addr;\n    }\n\n    # 系统接口\n    location /system/ {\n        proxy_pass http://127.0.0.1:8000;\n    }\n\n    # 验证码\n    location /captcha/ {\n        proxy_pass http://127.0.0.1:8000;\n    }\n\n    # 附件访问\n    location /attachment/ {\n        proxy_pass http://127.0.0.1:8000;\n    }\n\n    # WebSocket\n    location /socket/ {\n        proxy_pass http://127.0.0.1:8000;\n        proxy_http_version 1.1;\n        proxy_set_header Upgrade $http_upgrade;\n        proxy_set_header Connection \"upgrade\";\n        proxy_read_timeout 86400;\n    }\n\n    # Gzip\n    gzip on;\n    gzip_types text/plain text/css application/json application/javascript text/xml;\n    gzip_min_length 1024;\n}\n```\n\n## Docker 部署\n\n### Dockerfile（后端）\n\n```dockerfile\nFROM golang:1.24-alpine AS builder\nWORKDIR /app\nCOPY server/ .\nRUN go build -o xygoadmin main.go\n\nFROM alpine:latest\nWORKDIR /app\nCOPY --from=builder /app/xygoadmin .\nCOPY --from=builder /app/manifest/config/ ./manifest/config/\nEXPOSE 8000\nCMD [\"./xygoadmin\"]\n```\n\n### docker-compose.yml\n\n```yaml\nversion: ''3.8''\nservices:\n  app:\n    build: .\n    ports:\n      - \"8000:8000\"\n    depends_on:\n      - db\n      - redis\n    environment:\n      - GF_GCFG_FILE=config.yaml\n\n  db:\n    image: postgres:15\n    environment:\n      POSTGRES_DB: xygoadmin\n      POSTGRES_PASSWORD: 123456\n    volumes:\n      - pgdata:/var/lib/postgresql/data\n\n  redis:\n    image: redis:7-alpine\n    ports:\n      - \"6379:6379\"\n\nvolumes:\n  pgdata:\n```\n\n## 进程管理\n\n生产环境建议使用 systemd 或 supervisor 管理后端进程：\n\n```ini\n# /etc/systemd/system/xygoadmin.service\n[Unit]\nDescription=XYGo Admin Server\nAfter=network.target\n\n[Service]\nType=simple\nUser=www\nWorkingDirectory=/var/www/xygoadmin/server\nExecStart=/var/www/xygoadmin/server/xygoadmin\nRestart=always\nRestartSec=5\n\n[Install]\nWantedBy=multi-user.target\n```',
'XYGo Admin', 0, 50, 1, 0, '["部署","Docker","Nginx"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- WEB端专项 > 网络请求 (category_id=301)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(12, 301, '网络请求', 'http-request', '', 'Axios 封装、三套请求实例与拦截器机制',
E'# 网络请求\n\n## 架构设计\n\n项目基于 Axios 封装了统一的 HTTP 请求层，位于 `web/src/utils/http/`：\n\n```\nutils/http/\n├── index.ts      # 核心封装：Axios 实例、拦截器、请求方法\n├── status.ts     # 业务状态码定义\n└── error.ts      # 自定义 HttpError 类\n```\n\n## 三套请求实例\n\n通过 `createPrefixedApi(prefix)` 工厂函数创建带前缀的请求实例：\n\n```typescript\n// 后台管理接口 — 自动注入 Bearer Token\nexport const adminRequest = createPrefixedApi(''/admin'')\n\n// 前台会员接口 — 自动注入 Xy-User-Token\nexport const memberRequest = createPrefixedApi(''/member'')\n\n// 前台公共接口 — 无需 Token\nexport const siteRequest = createPrefixedApi(''/site'')\n```\n\n每个实例提供 5 个方法：\n\n```typescript\nadminRequest.get<T>({ url, params?, config? })\nadminRequest.post<T>({ url, params?, config? })\nadminRequest.put<T>({ url, params?, config? })\nadminRequest.del<T>({ url, params?, config? })\nadminRequest.request<T>(config)\n```\n\n## 使用示例\n\n```typescript\n// API 文件 — api/backend/cms/doc.ts\nimport { adminRequest } from ''@/utils/http''\n\nexport function fetchDocList(params: any) {\n  return adminRequest.get({ url: ''/cmsDoc/list'', params })\n}\n\nexport function fetchSaveDoc(data: any) {\n  return adminRequest.post({ url: ''/cmsDoc/edit'', params: data })\n}\n\nexport function fetchDeleteDoc(id: number) {\n  return adminRequest.post({ url: ''/cmsDoc/delete'', params: { id } })\n}\n```\n\n## 拦截器\n\n### 请求拦截器\n\n- 根据 URL 前缀自动区分 Token 类型\n- `/admin` 开头 → 注入 `Authorization: Bearer <token>`\n- `/member` 开头 → 注入 `Xy-User-Token: <token>`\n- 其他 → 不注入 Token\n\n### 响应拦截器\n\n| 业务码 | 处理方式 |\n|--------|----------|\n| 0 (success) | 返回 `response.data.data` |\n| -1 (error) | ElMessage 提示错误信息 |\n| 61 (unauthorized) | 清除 Token，跳转登录页（3 秒防抖） |\n| 10010 (kickedOut) | 弹窗提示被踢下线 |\n\n## 配置\n\n- baseURL：来自环境变量 `VITE_API_URL`\n- 超时时间：15 秒\n- 失败重试：可配置（默认关闭）',
'XYGo Admin', 0, 100, 1, 0, '["HTTP","Axios"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- WEB端专项 > 状态管理 (category_id=302)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(13, 302, '状态管理', 'state-management', '', 'Pinia 3 状态管理与持久化策略',
E'# 状态管理\n\n## 概述\n\n项目使用 **Pinia 3** + **pinia-plugin-persistedstate** 进行状态管理，Store 文件位于 `web/src/store/modules/`。\n\n## 核心 Store\n\n| Store | 文件 | 说明 |\n|-------|------|------|\n| useUserStore | `modules/user.ts` | 后台管理员状态（Token、用户信息、语言、锁屏） |\n| useMemberStore | `modules/member.ts` | 前台会员状态（独立 Token、会员信息） |\n| useSiteStore | `modules/site.ts` | 站点信息（站名、Logo、主题色、ICP） |\n| useMenuStore | `modules/menu.ts` | 后台菜单状态 |\n| useSettingStore | `modules/setting.ts` | 系统设置（主题、布局、颜色） |\n| useWorktabStore | `modules/worktab.ts` | 工作标签页状态 |\n| useTableStore | `modules/table.ts` | 表格配置状态 |\n| useMemberMenuStore | `modules/memberMenu.ts` | 前台会员菜单 |\n\n## 使用示例\n\n```typescript\nimport { useUserStore } from ''@/store/modules/user''\n\nconst userStore = useUserStore()\n\n// 读取状态\nconsole.log(userStore.token)\nconsole.log(userStore.userInfo)\n\n// 修改状态\nuserStore.setToken(''new-token'')\nuserStore.setUserInfo({ username: ''admin'' })\n\n// 清除状态（登出）\nuserStore.logout()\n```\n\n## 持久化策略\n\n使用 `StorageKeyManager` 生成版本化存储键：\n\n```\n格式：sys-v{version}-{storeId}\n示例：sys-v3.0-user\n```\n\n支持跨版本数据迁移，版本升级时自动清理旧数据。\n\n```typescript\n// store/index.ts\nimport { createPinia } from ''pinia''\nimport piniaPluginPersistedstate from ''pinia-plugin-persistedstate''\n\nconst pinia = createPinia()\npinia.use(piniaPluginPersistedstate)\n```\n\n## 前后台 Token 隔离\n\n- 后台管理员 Token 存储在 `useUserStore`，通过 `Authorization: Bearer` 传递\n- 前台会员 Token 存储在 `useMemberStore`，通过 `Xy-User-Token` Header 传递\n- 两套 Token 完全独立，互不影响',
'XYGo Admin', 0, 90, 1, 0, '["Pinia","状态管理"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- WEB端专项 > 图标使用 (category_id=303)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(14, 303, '图标使用', 'icon-usage', '', 'ArtSvgIcon 组件与 Remix Icon 图标库使用指南',
E'# 图标使用\n\n## 图标体系\n\n项目基于 **Iconify** 生态，统一使用 **Remix Icon** 图标库，通过 `ArtSvgIcon` 组件引用。\n\n## 基本用法\n\n```vue\n<template>\n  <!-- 基础用法 -->\n  <ArtSvgIcon icon=\"ri:home-line\" />\n\n  <!-- 设置大小和颜色 -->\n  <ArtSvgIcon icon=\"ri:settings-3-line\" class=\"text-2xl text-blue-500\" />\n\n  <!-- 在按钮中使用 -->\n  <ElButton type=\"primary\">\n    <ArtSvgIcon icon=\"ri:add-line\" class=\"text-sm mr-1\" />\n    新增\n  </ElButton>\n</template>\n```\n\n## 图标命名规则\n\nRemix Icon 的命名格式：`ri:{name}-{style}`\n\n| 风格 | 后缀 | 示例 |\n|------|------|------|\n| 线性 | `-line` | `ri:home-line` |\n| 填充 | `-fill` | `ri:home-fill` |\n\n## 查找图标\n\n- [Remix Icon 官网](https://remixicon.com/) — 搜索和预览\n- [Iconify 图标集](https://icones.js.org/collection/ri) — 在线浏览\n\n## 支持的图标库\n\n除了 Remix Icon，项目还支持：\n\n| 图标库 | 前缀 | 说明 |\n|--------|------|------|\n| Remix Icon | `ri:` | 主图标库（推荐） |\n| SVG Spinners | `svg-spinners:` | 加载动画图标 |\n| Material Line | `line-md:` | Material 风格动画图标 |\n\n```vue\n<!-- 加载动画 -->\n<ArtSvgIcon icon=\"svg-spinners:3-dots-fade\" class=\"text-2xl\" />\n\n<!-- Material 动画图标 -->\n<ArtSvgIcon icon=\"line-md:phone-call-twotone-loop\" class=\"text-2xl\" />\n```\n\n## 离线模式\n\n内网环境下，可以启用离线图标加载。编辑 `utils/ui/iconify-loader.ts`：\n\n```typescript\nimport { addCollection } from ''@iconify/vue''\nimport riIcons from ''@iconify-json/ri/icons.json''\n\naddCollection(riIcons)\n```\n\n需要先安装图标集包：\n\n```bash\npnpm add -D @iconify-json/ri\n```',
'XYGo Admin', 0, 80, 1, 0, '["图标","Remix Icon"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- WEB端专项 > 表格组件 (category_id=304)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(15, 304, '表格组件', 'table-component', '', 'ArtTable 和 ArtTableHeader 组件使用指南',
E'# 表格组件\n\n## ArtTable\n\n`ArtTable` 是对 Element Plus `ElTable` 的封装，提供统一的样式和加载状态。\n\n### 基本用法\n\n```vue\n<template>\n  <ArtTable :loading=\"loading\" :data=\"tableData\">\n    <ElTableColumn prop=\"title\" label=\"标题\" min-width=\"200\" show-overflow-tooltip />\n    <ElTableColumn prop=\"status\" label=\"状态\" width=\"80\" align=\"center\">\n      <template #default=\"{ row }\">\n        <ElTag :type=\"row.status === 1 ? ''success'' : ''danger''\" size=\"small\">\n          {{ row.status === 1 ? ''正常'' : ''禁用'' }}\n        </ElTag>\n      </template>\n    </ElTableColumn>\n    <ElTableColumn label=\"操作\" width=\"150\" fixed=\"right\">\n      <template #default=\"{ row }\">\n        <ElButton link type=\"primary\" size=\"small\" @click=\"handleEdit(row)\">编辑</ElButton>\n        <ElButton link type=\"danger\" size=\"small\" @click=\"handleDelete(row.id)\">删除</ElButton>\n      </template>\n    </ElTableColumn>\n  </ArtTable>\n</template>\n```\n\n### Props\n\n| 属性 | 类型 | 默认值 | 说明 |\n|------|------|--------|------|\n| data | Array | [] | 表格数据 |\n| loading | Boolean | false | 加载状态 |\n\n## ArtTableHeader\n\n表格头部工具栏，提供刷新按钮和自定义插槽。\n\n```vue\n<template>\n  <ArtTableHeader :loading=\"loading\" @refresh=\"loadData\">\n    <template #left>\n      <ElButton type=\"primary\" @click=\"handleAdd\">新增</ElButton>\n      <ElButton @click=\"handleExport\">导出</ElButton>\n    </template>\n  </ArtTableHeader>\n</template>\n```\n\n### Events\n\n| 事件 | 说明 |\n|------|------|\n| refresh | 点击刷新按钮时触发 |\n\n### Slots\n\n| 插槽 | 说明 |\n|------|------|\n| left | 左侧操作区域 |\n| right | 右侧操作区域 |\n\n## 完整示例\n\n```vue\n<template>\n  <ElCard shadow=\"never\">\n    <ArtTableHeader :loading=\"loading\" @refresh=\"loadData\">\n      <template #left>\n        <ElButton type=\"primary\" v-auth=\"''add''\">新增</ElButton>\n      </template>\n    </ArtTableHeader>\n\n    <ArtTable :loading=\"loading\" :data=\"tableData\">\n      <!-- 列定义 -->\n    </ArtTable>\n\n    <div class=\"art-pagination\">\n      <ElPagination\n        v-model:current-page=\"page\"\n        v-model:page-size=\"pageSize\"\n        :total=\"total\"\n        layout=\"total, sizes, prev, pager, next, jumper\"\n        @size-change=\"loadData\"\n        @current-change=\"loadData\"\n      />\n    </div>\n  </ElCard>\n</template>\n```',
'XYGo Admin', 0, 70, 1, 0, '["表格","组件"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- WEB端专项 > 表单组件 (category_id=305)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(16, 305, '表单组件', 'form-component', '', 'Element Plus 表单最佳实践与内置表单组件',
E'# 表单组件\n\n## Element Plus 表单\n\n项目中的表单统一使用 Element Plus 的 `ElForm` 组件，配合 `ElDialog` 实现弹窗编辑。\n\n### 标准表单模式\n\n```vue\n<template>\n  <ElDialog v-model=\"visible\" :title=\"isEdit ? ''编辑'' : ''新增''\" width=\"600px\">\n    <ElForm ref=\"formRef\" :model=\"formData\" :rules=\"rules\" label-width=\"80px\">\n      <ElFormItem label=\"名称\" prop=\"name\">\n        <ElInput v-model=\"formData.name\" placeholder=\"请输入名称\" />\n      </ElFormItem>\n      <ElFormItem label=\"状态\" prop=\"status\">\n        <ElSelect v-model=\"formData.status\">\n          <ElOption label=\"正常\" :value=\"1\" />\n          <ElOption label=\"禁用\" :value=\"2\" />\n        </ElSelect>\n      </ElFormItem>\n    </ElForm>\n    <template #footer>\n      <ElButton @click=\"visible = false\">取消</ElButton>\n      <ElButton type=\"primary\" @click=\"handleSubmit\" :loading=\"submitting\">保存</ElButton>\n    </template>\n  </ElDialog>\n</template>\n```\n\n### 验证规则\n\n```typescript\nconst rules: FormRules = {\n  name: [{ required: true, message: ''请输入名称'', trigger: ''blur'' }],\n  status: [{ required: true, message: ''请选择状态'', trigger: ''change'' }]\n}\n```\n\n## 内置表单组件\n\n| 组件 | 说明 |\n|------|------|\n| ArtSearchBar | 搜索栏组件 |\n| ArtForm | 通用表单生成器 |\n| ArtImageUpload | 图片上传（支持裁剪、多图） |\n| ArtFileUpload | 文件上传 |\n| ArtFileSelector | 从附件库选择文件 |\n| ArtIconSelector | 图标选择器 |\n| ArtColorPicker | 颜色选择器 |\n| ArtArrayEditor | 数组编辑器 |\n| ArtCronDesigner | Cron 表达式设计器 |\n| ArtWangEditor | 富文本编辑器 |\n| ArtClickCaptcha | 点选验证码 |\n| ArtDragVerify | 拖拽验证 |\n| ArtExcelImport | Excel 导入 |\n| ArtExcelExport | Excel 导出 |\n\n## 图片上传示例\n\n```vue\n<ElFormItem label=\"封面图\">\n  <ArtImageUpload v-model=\"formData.cover\" :limit=\"1\" />\n</ElFormItem>\n```\n\n## 富文本编辑器\n\n项目内置两种富文本方案：\n\n- **WangEditor**：适合简单富文本场景\n- **md-editor-v3**：适合 Markdown 文档编辑\n\n```vue\n<!-- WangEditor -->\n<ArtWangEditor v-model=\"formData.content\" />\n\n<!-- Markdown 编辑器 -->\n<MdEditor v-model=\"formData.content\" />\n```',
'XYGo Admin', 0, 60, 1, 0, '["表单","组件"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- WEB端专项 > CSS与样式 (category_id=306)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(17, 306, 'CSS 与样式', 'css-style', '', 'Tailwind CSS 4 + Clay 拟态阴影设计体系',
E'# CSS 与样式\n\n## 技术方案\n\n- **Tailwind CSS 4**：原子化 CSS，通过 `@tailwindcss/vite` 插件集成\n- **SCSS**：全局变量和 Mixin\n- **Clay 拟态设计**：项目独创的阴影体系\n\n## Clay 拟态阴影\n\n项目的核心视觉特色，通过多层阴影模拟黏土质感：\n\n### 阴影变量\n\n```scss\n// 卡片阴影\n.shadow-clay-card {\n  box-shadow:\n    16px 16px 32px rgba(165, 175, 190, 0.3),\n    -10px -10px 24px rgba(255, 255, 255, 0.9),\n    inset 6px 6px 12px rgba(90, 141, 238, 0.03),\n    inset -6px -6px 12px rgba(255, 255, 255, 1);\n}\n\n// 按钮阴影\n.shadow-clay-btn {\n  box-shadow:\n    12px 12px 24px rgba(90, 141, 238, 0.3),\n    -8px -8px 16px rgba(255, 255, 255, 0.4),\n    inset 4px 4px 8px rgba(255, 255, 255, 0.4),\n    inset -4px -4px 8px rgba(0, 0, 0, 0.05);\n}\n\n// 按压效果\n.shadow-clay-pressed {\n  box-shadow:\n    inset 10px 10px 20px #e0e5ec,\n    inset -10px -10px 20px #ffffff;\n}\n\n// 深层阴影（Hero 区域）\n.shadow-clay-deep {\n  box-shadow:\n    30px 30px 60px #d1d9e6,\n    -30px -30px 60px #ffffff,\n    inset 10px 10px 20px rgba(90, 141, 238, 0.05),\n    inset -10px -10px 20px rgba(255, 255, 255, 0.8);\n}\n```\n\n### 配色体系\n\n```scss\n.text-clay-foreground { color: #32325d; }  // 主文字\n.text-clay-muted { color: #8898aa; }       // 次要文字\n.text-clay-accent { color: #5a8dee; }      // 强调色\n.bg-clay-accent { background: #5a8dee; }   // 强调背景\n```\n\n## Tailwind CSS 使用\n\n项目使用 Tailwind CSS v4，通过 Vite 插件自动集成，无需独立配置文件。\n\n### 常用类名\n\n```vue\n<template>\n  <!-- 布局 -->\n  <div class=\"flex items-center gap-4 p-6\">\n  \n  <!-- 圆角卡片 -->\n  <div class=\"bg-white/70 backdrop-blur-xl rounded-[32px] p-8\">\n  \n  <!-- 响应式 -->\n  <div class=\"grid lg:grid-cols-12 gap-8\">\n  \n  <!-- 文字 -->\n  <h1 class=\"font-heading font-black text-3xl text-clay-foreground\">\n</template>\n```\n\n## 全局 SCSS\n\nVite 配置中自动注入两个全局 SCSS 文件：\n\n- `el-light.scss`：Element Plus 主题变量覆盖\n- `mixin.scss`：常用 Mixin（响应式断点、文字截断等）',
'XYGo Admin', 0, 50, 1, 0, '["CSS","Tailwind","Clay"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- WEB端专项 > 内置组件库 (category_id=307)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(18, 307, '内置组件库', 'components', '', '项目内置的 50+ 公共组件一览',
E'# 内置组件库\n\n项目内置了 50+ 公共组件，按功能分类组织在 `web/src/components/` 目录下。\n\n## 图表组件（9 个）\n\n基于 ECharts 6 封装，开箱即用：\n\n| 组件 | 说明 |\n|------|------|\n| ArtBarChart | 柱状图 |\n| ArtLineChart | 折线图 |\n| ArtRingChart | 环形图 |\n| ArtRadarChart | 雷达图 |\n| ArtScatterChart | 散点图 |\n| ArtKLineChart | K 线图 |\n| ArtMapChart | 地图图表 |\n| ArtHBarChart | 水平柱状图 |\n| ArtDualBarCompareChart | 双向对比柱状图 |\n\n## 表单组件（16 个）\n\n| 组件 | 说明 |\n|------|------|\n| ArtSearchBar | 搜索栏 |\n| ArtForm | 通用表单生成器 |\n| ArtWangEditor | 富文本编辑器 |\n| ArtImageUpload | 图片上传 |\n| ArtFileUpload | 文件上传 |\n| ArtFileSelector | 文件选择器 |\n| ArtIconSelector | 图标选择器 |\n| ArtColorPicker | 颜色选择器 |\n| ArtArrayEditor | 数组编辑器 |\n| ArtFieldEditor | 字段编辑器 |\n| ArtClickCaptcha | 点选验证码 |\n| ArtCronDesigner | Cron 表达式设计器 |\n| ArtDragVerify | 拖拽验证 |\n| ArtExcelImport | Excel 导入 |\n| ArtExcelExport | Excel 导出 |\n| ArtButtonTable / ArtButtonMore | 按钮组件 |\n\n## 布局组件（20+ 个）\n\n| 组件 | 说明 |\n|------|------|\n| ArtHeaderBar | 顶部导航栏 |\n| ArtSidebarMenu | 侧边栏菜单 |\n| ArtHorizontalMenu | 水平菜单 |\n| ArtMixedMenu | 混合菜单 |\n| ArtBreadcrumb | 面包屑 |\n| ArtWorkTab | 工作标签页 |\n| ArtPageContent | 页面内容容器 |\n| ArtSettingsPanel | 设置面板 |\n| ArtScreenLock | 锁屏 |\n| ArtGlobalSearch | 全局搜索 |\n| ArtFastEnter | 快速入口 |\n| ArtChatWindow | 聊天窗口 |\n| ArtNotification | 通知 |\n| ArtFireworksEffect | 烟花特效 |\n\n## 媒体组件\n\n| 组件 | 说明 |\n|------|------|\n| ArtVideoPlayer | 视频播放器（基于 xgplayer） |\n| ArtCutterImg | 图片裁剪 |\n\n## 文字特效\n\n| 组件 | 说明 |\n|------|------|\n| ArtTextScroll | 文字滚动 |\n| ArtCountTo | 数字动画 |\n| ArtFestivalTextScroll | 节日文字滚动 |\n\n## 其他\n\n| 组件 | 说明 |\n|------|------|\n| ArtWatermark | 水印 |\n| ArtMenuRight | 右键菜单 |\n| ArtSvgIcon | SVG 图标 |\n\n## 自定义指令\n\n| 指令 | 说明 |\n|------|------|\n| v-auth | 按钮级权限控制 |\n| v-roles | 角色级权限控制 |\n| v-ripple | Material Design 水波纹效果 |\n| v-highlight | 代码高亮 |',
'XYGo Admin', 0, 40, 1, 0, '["组件","组件库"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- Server端专项 > GoFrame基础 (category_id=401)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(19, 401, 'GoFrame 基础', 'goframe-basic', '', 'GoFrame v2 框架核心概念与配置文件说明',
E'# GoFrame 基础\n\n## 框架简介\n\nXYGo Admin 后端基于 [GoFrame v2](https://goframe.org/) 构建，GoFrame 是一款模块化、高性能的 Go 应用开发框架。\n\n## 核心概念\n\n### 项目结构约定\n\nGoFrame 推荐的标准项目结构：\n\n```\nserver/\n├── api/          # 对外接口定义（请求/响应结构体）\n├── internal/     # 内部逻辑（不可被外部包引用）\n│   ├── cmd/      # 入口命令\n│   ├── controller/\n│   ├── logic/\n│   ├── service/\n│   ├── model/\n│   └── dao/\n├── manifest/\n│   └── config/   # 配置文件\n├── hack/         # CLI 工具配置\n└── main.go\n```\n\n### g.Meta 声明式路由\n\nGoFrame 使用结构体 tag 声明路由，无需手动注册：\n\n```go\ntype HelloReq struct {\n    g.Meta `path:\"/hello\" method:\"get\" tags:\"示例\" summary:\"Hello接口\"`\n    Name   string `json:\"name\" v:\"required#请输入名称\"`\n}\n\ntype HelloRes struct {\n    Message string `json:\"message\"`\n}\n```\n\n### 自动校验\n\n通过 `v` tag 实现参数自动校验：\n\n```go\nName     string `v:\"required|length:2,20#名称不能为空|长度2-20\"`\nEmail    string `v:\"required|email\"`\nAge      int    `v:\"between:1,150\"`\n```\n\n## 配置文件\n\n主配置文件位于 `server/manifest/config/config.yaml`：\n\n```yaml\nserver:\n  address: \":8000\"\n  serverRoot: \"resource/public\"\n\ndatabase:\n  default:\n    link: \"pgsql:postgres:123456@tcp(127.0.0.1:5432)/xygoadmin\"\n    debug: true\n    prefix: \"xy_\"\n\nredis:\n  default:\n    address: 127.0.0.1:6379\n    db: 0\n\nlogger:\n  path: \"logs\"\n  level: \"all\"\n  stdout: true\n```\n\n## CLI 工具\n\nGoFrame CLI（`gf`）提供代码生成能力：\n\n```bash\n# 生成 DAO + Entity + DO\ngf gen dao\n\n# 生成 Service 接口\ngf gen service\n\n# 运行项目（支持热重载）\ngf run main.go\n```\n\nCLI 配置文件：`server/hack/config.yaml`\n\n```yaml\ngfcli:\n  gen:\n    dao:\n      link: \"pgsql:postgres:123456@tcp(127.0.0.1:5432)/xygonew\"\n      removePrefix: \"xy_\"\n      jsonCase: \"CamelLower\"\n    service:\n      srcFolder: \"internal/logic\"\n      dstFolder: \"internal/service\"\n```',
'XYGo Admin', 0, 100, 1, 0, '["GoFrame","框架"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- Server端专项 > 控制器开发 (category_id=402)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(20, 402, '控制器开发', 'controller', '', 'Controller 层编写规范与最佳实践',
E'# 控制器开发\n\n## 职责定义\n\nController 层只负责：\n1. 接收请求参数（由框架自动绑定）\n2. 调用 Service 层处理业务\n3. 返回响应结果\n\n**不要在 Controller 中编写业务逻辑。**\n\n## 编写规范\n\n### 1. 定义 API 结构体\n\n在 `api/admin/` 目录下定义请求和响应：\n\n```go\n// api/admin/admin_example.go\npackage admin\n\nimport \"github.com/gogf/gf/v2/frame/g\"\n\n// 列表\ntype ExampleListReq struct {\n    g.Meta   `path:\"/example/list\" method:\"get\" tags:\"示例管理\" summary:\"列表\"`\n    Page     int    `json:\"page\" d:\"1\"`\n    PageSize int    `json:\"pageSize\" d:\"20\"`\n    Title    string `json:\"title\"`\n}\ntype ExampleListRes struct {\n    List  interface{} `json:\"list\"`\n    Total int         `json:\"total\"`\n}\n\n// 编辑（新增+修改）\ntype ExampleEditReq struct {\n    g.Meta `path:\"/example/edit\" method:\"post\" tags:\"示例管理\" summary:\"编辑\"`\n    Id     uint64 `json:\"id\"`\n    Title  string `json:\"title\" v:\"required#请输入标题\"`\n    Status int    `json:\"status\" d:\"1\"`\n}\ntype ExampleEditRes struct{}\n\n// 删除\ntype ExampleDeleteReq struct {\n    g.Meta `path:\"/example/delete\" method:\"post\" tags:\"示例管理\" summary:\"删除\"`\n    Id     uint64 `json:\"id\" v:\"required#请选择要删除的数据\"`\n}\ntype ExampleDeleteRes struct{}\n```\n\n### 2. 编写 Controller\n\n```go\n// internal/controller/admin/example.go\npackage admin\n\nimport (\n    \"context\"\n    api \"xygo/api/admin\"\n    \"xygo/internal/service\"\n)\n\nvar Example = cExample{}\ntype cExample struct{}\n\nfunc (c *cExample) List(ctx context.Context, req *api.ExampleListReq) (res *api.ExampleListRes, err error) {\n    return service.Example().List(ctx, req)\n}\n\nfunc (c *cExample) Edit(ctx context.Context, req *api.ExampleEditReq) (res *api.ExampleEditRes, err error) {\n    return service.Example().Edit(ctx, req)\n}\n\nfunc (c *cExample) Delete(ctx context.Context, req *api.ExampleDeleteReq) (res *api.ExampleDeleteRes, err error) {\n    return service.Example().Delete(ctx, req)\n}\n```\n\n### 3. 注册路由\n\n在 `internal/cmd/cmd.go` 中将 Controller 注册到路由组：\n\n```go\n// /admin 路由组\ngroup.Group(\"/admin\", func(group *ghttp.RouterGroup) {\n    group.Middleware(middleware.AdminAuth)\n    group.Bind(\n        controller.Admin.Example,\n        // ... 其他控制器\n    )\n})\n```',
'XYGo Admin', 0, 90, 1, 0, '["Controller","控制器"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- Server端专项 > 业务逻辑层 (category_id=403)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(21, 403, '业务逻辑层', 'logic-service', '', 'Logic 层与 Service 层的开发规范',
E'# 业务逻辑层\n\n## 架构说明\n\n- **Service 层**：定义接口（由 `gf gen service` 自动生成，勿手动修改）\n- **Logic 层**：实现接口（核心业务代码写在这里）\n\n## 编写 Logic\n\n### 1. 创建 Logic 文件\n\n```go\n// internal/logic/example/example.go\npackage example\n\nimport (\n    \"context\"\n    api \"xygo/api/admin\"\n    \"xygo/internal/dao\"\n    \"xygo/internal/service\"\n)\n\nfunc init() {\n    service.RegisterExample(New())\n}\n\nfunc New() *sExample {\n    return &sExample{}\n}\n\ntype sExample struct{}\n```\n\n### 2. 实现业务方法\n\n```go\n// 列表查询\nfunc (s *sExample) List(ctx context.Context, req *api.ExampleListReq) (res *api.ExampleListRes, err error) {\n    res = &api.ExampleListRes{}\n    m := dao.Example.Ctx(ctx)\n\n    if req.Title != \"\" {\n        m = m.WhereLike(\"title\", \"%\"+req.Title+\"%\")\n    }\n\n    res.Total, err = m.Count()\n    if err != nil {\n        return\n    }\n\n    err = m.Page(req.Page, req.PageSize).\n        OrderDesc(\"id\").\n        Scan(&res.List)\n    return\n}\n\n// 编辑（新增+修改）\nfunc (s *sExample) Edit(ctx context.Context, req *api.ExampleEditReq) (res *api.ExampleEditRes, err error) {\n    data := do.Example{\n        Title:  req.Title,\n        Status: req.Status,\n    }\n    if req.Id > 0 {\n        _, err = dao.Example.Ctx(ctx).Where(\"id\", req.Id).Data(data).Update()\n    } else {\n        _, err = dao.Example.Ctx(ctx).Data(data).Insert()\n    }\n    return\n}\n\n// 删除\nfunc (s *sExample) Delete(ctx context.Context, req *api.ExampleDeleteReq) (res *api.ExampleDeleteRes, err error) {\n    _, err = dao.Example.Ctx(ctx).Where(\"id\", req.Id).Delete()\n    return\n}\n```\n\n### 3. 注册到 logic.go\n\n在 `internal/logic/logic.go` 中添加导入：\n\n```go\npackage logic\n\nimport (\n    _ \"xygo/internal/logic/example\"\n    // ... 其他模块\n)\n```\n\n### 4. 生成 Service 接口\n\n```bash\ngf gen service\n```\n\n这会自动在 `internal/service/` 下生成 `example.go`，包含接口定义和注册函数。\n\n## 注意事项\n\n- Logic 中的 `init()` 函数负责将实现注册到 Service\n- 所有数据库操作通过 DAO 层进行，不要直接写 SQL\n- 事务操作使用 `dao.Example.Transaction(ctx, func(ctx context.Context, tx gdb.TX) error { ... })`',
'XYGo Admin', 0, 80, 1, 0, '["Logic","Service"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- Server端专项 > 数据库操作 (category_id=404)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(22, 404, '数据库操作', 'database', '', 'DAO / Entity / DO 三层模型与数据库方言适配',
E'# 数据库操作\n\n## 三层模型\n\n| 层 | 目录 | 说明 | 是否自动生成 |\n|----|------|------|-------------|\n| Entity | `model/entity/` | 数据库表结构映射，字段与表一一对应 | ✅ gf gen dao |\n| DO | `model/do/` | 数据操作对象，所有字段类型为 `any`，用于 Where/Data | ✅ gf gen dao |\n| DAO | `dao/` | 数据访问对象，提供 `Ctx(ctx)` 获取 Model | ✅ gf gen dao |\n\n### Entity 示例\n\n```go\n// model/entity/admin_user.go（自动生成，勿修改）\ntype AdminUser struct {\n    Id        uint64 `json:\"id\"        orm:\"id\"`\n    Username  string `json:\"username\"  orm:\"username\"`\n    Password  string `json:\"password\"  orm:\"password\"`\n    Status    int    `json:\"status\"    orm:\"status\"`\n    CreatedAt uint64 `json:\"createdAt\" orm:\"created_at\"`\n}\n```\n\n### DAO 双层结构\n\n```go\n// dao/internal/admin_user.go（自动生成，勿修改）\n// 包含表名、字段名常量、Ctx() 方法\n\n// dao/admin_user.go（可扩展）\ntype adminUserDao struct { *internal.AdminUserDao }\nvar AdminUser = adminUserDao{internal.NewAdminUserDao()}\n\n// 可以在这里添加自定义方法\nfunc (d *adminUserDao) FindByUsername(ctx context.Context, username string) (*entity.AdminUser, error) {\n    var user entity.AdminUser\n    err := d.Ctx(ctx).Where(\"username\", username).Scan(&user)\n    return &user, err\n}\n```\n\n## 常用操作\n\n```go\n// 查询列表\nvar list []entity.AdminUser\nerr := dao.AdminUser.Ctx(ctx).Page(1, 20).OrderDesc(\"id\").Scan(&list)\n\n// 条件查询\nm := dao.AdminUser.Ctx(ctx)\nif username != \"\" {\n    m = m.WhereLike(\"username\", \"%\"+username+\"%\")\n}\nif status > 0 {\n    m = m.Where(\"status\", status)\n}\n\n// 新增\n_, err := dao.AdminUser.Ctx(ctx).Data(do.AdminUser{\n    Username: \"newuser\",\n    Status:   1,\n}).Insert()\n\n// 更新\n_, err := dao.AdminUser.Ctx(ctx).Where(\"id\", id).Data(do.AdminUser{\n    Status: 2,\n}).Update()\n\n// 删除\n_, err := dao.AdminUser.Ctx(ctx).Where(\"id\", id).Delete()\n\n// 事务\nerr := dao.AdminUser.Transaction(ctx, func(ctx context.Context, tx gdb.TX) error {\n    // 事务内的操作\n    return nil\n})\n```\n\n## 数据库方言适配\n\n项目通过 `library/dbdialect/` 包实现 MySQL 和 PostgreSQL 的兼容：\n\n- 类型映射：自动转换数据类型差异\n- DDL 生成：代码生成器创建表时自动适配语法\n- 表前缀：统一使用 `xy_`，在 CLI 配置中通过 `removePrefix` 去除',
'XYGo Admin', 0, 70, 1, 0, '["数据库","DAO","ORM"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- Server端专项 > 文件上传 (category_id=405)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(23, 405, '文件上传', 'file-upload', '', '多云存储驱动与文件上传配置',
E'# 文件上传\n\n## 存储驱动\n\n项目支持 4 种存储驱动，通过 `sys_config` 表的 `oss` 分组配置：\n\n| 驱动 | 说明 |\n|------|------|\n| local | 本地存储（默认） |\n| aliyun_oss | 阿里云 OSS |\n| tencent_cos | 腾讯云 COS |\n| qiniu | 七牛云存储 |\n\n## 配置方式\n\n在后台「系统配置」中设置上传参数：\n\n- **存储驱动**：选择使用哪种存储\n- **最大文件大小**：支持 kb/mb/gb 单位，如 `10mb`\n- **允许的文件后缀**：如 `jpg,png,gif,pdf,doc,xlsx`\n- **允许的 MIME 类型**：如 `image/*,application/pdf`\n\n### 云存储配置\n\n以阿里云 OSS 为例：\n- AccessKey ID\n- AccessKey Secret\n- Bucket 名称\n- Endpoint（如 `oss-cn-hangzhou.aliyuncs.com`）\n- 自定义域名（可选）\n\n## 上传接口\n\n```\nPOST /admin/upload/file\nContent-Type: multipart/form-data\n\n参数：file（文件）\n\n响应：\n{\n  \"code\": 0,\n  \"data\": {\n    \"url\": \"https://xxx.com/uploads/2025/01/abc.jpg\",\n    \"name\": \"abc.jpg\",\n    \"size\": 102400\n  }\n}\n```\n\n## 前端调用\n\n```typescript\n// 使用 ArtImageUpload 组件\n<ArtImageUpload v-model=\"formData.cover\" :limit=\"1\" />\n\n// 手动上传\nconst formData = new FormData()\nformData.append(''file'', file)\nconst res = await adminRequest.post({\n  url: ''/upload/file'',\n  params: formData,\n  headers: { ''Content-Type'': ''multipart/form-data'' }\n})\n```\n\n## 附件管理\n\n所有上传的文件会记录到 `sys_attachment` 表，可在后台「附件管理」中查看、搜索、删除。支持按文件类型筛选：图片、文档、音频、视频、压缩包等。',
'XYGo Admin', 0, 60, 1, 0, '["上传","OSS","存储"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- Server端专项 > 定时任务 (category_id=406)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(24, 406, '定时任务', 'cron-task', '', 'Cron 定时任务的配置、开发与管理',
E'# 定时任务\n\n## 功能概览\n\n- 可视化管理定时任务（增删改查）\n- 支持 Cron 表达式配置执行周期\n- 在线执行（手动触发一次）\n- 执行日志记录与查询\n- 任务分组管理\n\n## 任务注册\n\n在 `internal/crons/` 目录下注册任务：\n\n```go\n// internal/crons/example.go\npackage crons\n\nimport (\n    \"context\"\n    \"xygo/internal/library/cron\"\n)\n\nfunc init() {\n    cron.Register(\"example_task\", func(ctx context.Context) error {\n        // 你的任务逻辑\n        g.Log().Info(ctx, \"定时任务执行中...\")\n        return nil\n    })\n}\n```\n\n## 后台管理\n\n在后台「系统管理 → 定时任务」中：\n\n1. **新增任务**：选择已注册的任务标识，配置 Cron 表达式\n2. **启用/禁用**：控制任务是否参与调度\n3. **在线执行**：手动触发一次，立即执行\n4. **执行日志**：查看每次执行的结果和耗时\n\n## Cron 表达式\n\n```\n┌──────────── 秒 (0-59)\n│ ┌────────── 分 (0-59)\n│ │ ┌──────── 时 (0-23)\n│ │ │ ┌────── 日 (1-31)\n│ │ │ │ ┌──── 月 (1-12)\n│ │ │ │ │ ┌── 周 (0-6, 0=周日)\n│ │ │ │ │ │\n* * * * * *\n```\n\n常用示例：\n\n| 表达式 | 说明 |\n|--------|------|\n| `0 */5 * * * *` | 每 5 分钟 |\n| `0 0 2 * * *` | 每天凌晨 2 点 |\n| `0 0 0 1 * *` | 每月 1 号零点 |\n| `0 30 9 * * 1-5` | 工作日 9:30 |\n\n## 任务分组\n\n支持将任务按业务分组管理，方便查找和维护。',
'XYGo Admin', 0, 50, 1, 0, '["定时任务","Cron"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- Server端专项 > WebSocket (category_id=407)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(25, 407, 'WebSocket', 'websocket', '', '即时聊天模块的架构与开发指南',
E'# WebSocket\n\n## 架构设计\n\n项目基于 `gorilla/websocket` 实现即时通讯，采用 Hub 模式管理连接：\n\n```\nWebSocket 基础设施（internal/websocket/）\n├── init.go       # Start() 启动 Hub、WsHandler 处理连接\n├── client.go     # 客户端连接封装\n├── manager.go    # Hub 管理器（SendToUser/IsUserOnline）\n├── router.go     # 消息路由分发\n└── model.go      # WsResponse 等数据结构\n```\n\n## 连接流程\n\n```\n前端 WebSocket 连接\n  → /socket/ 端点\n    → WsAuth 中间件（JWT 鉴权）\n      → WsHandler 创建 Client\n        → 注册到 Hub Manager\n          → 开始收发消息\n```\n\n## 聊天功能\n\n聊天业务逻辑在 `internal/logic/chat/chat.go` 中实现：\n\n| 功能 | 方法 | 说明 |\n|------|------|------|\n| 会话列表 | Sessions | 获取单聊/群聊会话列表 |\n| 创建会话 | CreateSession | 单聊去重 + 群聊系统消息 |\n| 删除会话 | DeleteSession | 软删除（仅对当前用户） |\n| 消息列表 | Messages | 游标分页 + 发送者信息 |\n| 发送消息 | SendMessage | 写入 DB + 更新未读 + WS 推送 |\n| 标记已读 | MarkRead | 标记已读 + 推送已读回执 |\n| 联系人 | Contacts | 含部门/岗位/在线状态 |\n| 群聊管理 | GroupUpdate | 改名/加人/踢人 |\n| 未读总数 | UnreadTotal | 所有会话未读消息总数 |\n\n## 前端 WebSocket 客户端\n\n位于 `web/src/utils/socket/index.ts`，特性：\n\n- **单例模式**：全局只维护一个连接\n- **心跳检测**：定时发送 ping 保持连接\n- **指数退避重连**：断线后自动重连，间隔递增\n- **消息队列**：连接断开时缓存消息，恢复后自动发送\n- **连接超时**：超时自动断开并重试\n\n```typescript\nimport { useWebSocket } from ''@/utils/socket''\n\nconst ws = useWebSocket()\nws.connect()\nws.send({ type: ''chat'', data: { ... } })\nws.onMessage((msg) => { ... })\n```\n\n## Nginx 配置\n\nWebSocket 需要特殊的 Nginx 配置：\n\n```nginx\nlocation /socket/ {\n    proxy_pass http://127.0.0.1:8000;\n    proxy_http_version 1.1;\n    proxy_set_header Upgrade $http_upgrade;\n    proxy_set_header Connection \"upgrade\";\n    proxy_read_timeout 86400;\n}\n```',
'XYGo Admin', 0, 40, 1, 0, '["WebSocket","聊天"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 会员系统 > 会员管理 (category_id=501)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(26, 501, '会员管理', 'member-manage', '', '会员 CRUD、分组管理与会员菜单配置',
E'# 会员管理\n\n## 功能概览\n\n会员系统独立于后台管理员体系，拥有独立的认证、菜单和权限。\n\n### 后台管理功能\n\n| 功能 | 路径 | 说明 |\n|------|------|------|\n| 会员列表 | 会员管理 → 会员列表 | 会员 CRUD、状态管理 |\n| 会员分组 | 会员管理 → 会员分组 | 分组管理（如普通会员、VIP） |\n| 会员菜单 | 会员管理 → 会员菜单 | 前台会员中心的菜单配置 |\n| 登录日志 | 会员管理 → 登录日志 | 会员登录记录 |\n| 积分日志 | 会员管理 → 积分日志 | 积分变动记录 |\n| 资金日志 | 会员管理 → 资金日志 | 余额变动记录 |\n| 会员通知 | 会员管理 → 会员通知 | 站内通知管理 |\n\n## 会员数据结构\n\n`member` 表核心字段：\n\n| 字段 | 说明 |\n|------|------|\n| username | 用户名 |\n| password / salt | 密码 + 盐值 |\n| real_name | 真实姓名 |\n| mobile / email | 手机号 / 邮箱 |\n| avatar | 头像 |\n| group_id | 所属分组 |\n| score | 积分 |\n| money | 余额 |\n| status | 状态（正常/禁用） |\n| last_login_at | 最后登录时间 |\n\n## 会员分组\n\n通过分组实现会员等级管理：\n- 每个分组可配置名称、图标、排序\n- 会员只能属于一个分组\n- 可按分组筛选会员列表\n\n## 会员菜单\n\n前台会员中心的导航菜单通过后台配置，支持：\n- 树形菜单结构\n- 图标配置\n- 路由路径配置\n- 排序和显隐控制',
'XYGo Admin', 0, 100, 1, 0, '["会员","管理"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 会员系统 > 会员认证 (category_id=502)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(27, 502, '会员认证', 'member-auth', '', '会员登录注册与 JWT Token 机制',
E'# 会员认证\n\n## 认证体系\n\n会员认证独立于后台管理员，使用不同的 Token Header：\n\n| 对比项 | 后台管理员 | 前台会员 |\n|--------|-----------|----------|\n| Token Header | `Authorization: Bearer` | `Xy-User-Token` |\n| 中间件 | AdminAuth | MemberAuth |\n| Store | useUserStore | useMemberStore |\n| 路由前缀 | `/admin` | `/member` |\n\n## 登录方式\n\n系统支持三种登录方式：\n\n| 方式 | 适用场景 | 接口路径 | 获取方式 |\n|------|---------|---------|----------|\n| 账号密码登录 | Web 前台 | `POST /member/auth/login` | 用户名 + 密码 |\n| 微信小程序登录 | 小程序 / 小游戏 | `POST /wm/auth/login` | 微信 code |\n| 微信公众号登录 | 公众号 H5 网页 | `GET /wm/oa/auth/url` + `GET /wm/oa/auth/callback` | OAuth2 授权 |\n\n三种方式共享同一套会员体系（`xy_member` 表），登录后均返回 JWT Token，后续请求通过 `Xy-User-Token` Header 鉴权。\n\n## 一、账号密码登录\n\n```\n1. 用户输入账号密码\n2. 前端调用 POST /member/auth/login\n3. 后端校验密码（bcrypt 加密比对）\n4. 生成 JWT Token\n5. 返回 Token + 用户信息\n6. 前端存储到 useMemberStore（持久化）\n7. 后续请求自动注入 Xy-User-Token Header\n```\n\n## 二、微信小程序登录\n\n适用于微信小程序、小游戏场景，用户无需输入账号密码，通过微信授权一键登录。\n\n### 流程\n\n```\n1. 小程序端调用 uni.login() 获取微信临时 code\n2. 将 code 发送到 POST /wm/auth/login\n3. 后端从 xy_sys_config 读取 we_mapp 分组的 appid / appsecret\n4. 调用微信 jscode2session 接口，用 code 换取 openid + session_key\n5. 按 openid_mapp 字段查询 xy_member 表\n6. 若用户不存在则自动注册（用户名 wx_xxx、默认昵称"微信用户"）\n7. 复用 token.GenerateMember 生成 JWT Token\n8. 返回 {token, expiresIn, isNew}\n```\n\n### 接口定义\n\n**POST /wm/auth/login**\n\n请求参数：\n```json\n{\n  "code": "微信登录临时code"\n}\n```\n\n响应：\n```json\n{\n  "code": 0,\n  "data": {\n    "token": "eyJhbGciOi...",\n    "expiresIn": 7200,\n    "isNew": true\n  }\n}\n```\n\n### 后台配置\n\n在后台管理 → 系统配置 → 小程序配置中填写：\n- **微信小程序 AppID**（wmapp_appid）\n- **微信小程序 AppSecret**（wmapp_secret）\n\n### 白名单\n\n`/wm/auth/login` 已加入 MemberAuth 中间件白名单，无需携带 Token 即可访问。\n\n## 三、微信公众号登录（OAuth2 网页授权）\n\n适用于微信公众号内 H5 网页，用户在微信内打开页面后通过 OAuth2 授权登录，可获取微信昵称和头像。\n\n### 前置条件\n\n- 需要**认证的服务号**（或微信测试号）\n- 在微信公众平台 → 设置与开发 → 公众号设置 → 功能设置中配置**网页授权域名**\n\n### 流程\n\n```\n1. H5 前端调用 GET /wm/oa/auth/url?redirect=前端回跳地址\n2. 后端从 xy_sys_config 读取 we_oa 分组的 appid\n3. 拼接微信授权 URL 并返回\n4. 前端跳转到微信授权页面（window.location.href = url）\n5. 用户同意授权后，微信 302 回调到 /wm/oa/auth/callback?code=xxx\n6. 后端用 code 换取 access_token + openid\n7. 用 access_token 调用微信 userinfo 接口获取昵称/头像\n8. 按 openid_oa 字段查询 xy_member 表\n9. 若用户不存在则自动注册（携带微信昵称和头像）\n10. 复用 token.GenerateMember 生成 JWT Token\n11. 返回 {token, expiresIn, isNew}\n```\n\n### 接口定义\n\n**GET /wm/oa/auth/url**\n\n请求参数：\n| 参数 | 说明 |\n|------|------|\n| redirect | 授权完成后前端回跳地址 |\n\n响应：\n```json\n{\n  "code": 0,\n  "data": {\n    "url": "https://open.weixin.qq.com/connect/oauth2/authorize?appid=..."\n  }\n}\n```\n\n**GET /wm/oa/auth/callback**\n\n请求参数（微信回调自动携带）：\n| 参数 | 说明 |\n|------|------|\n| code | 微信授权码 |\n| state | 防伪校验值 |\n\n响应：\n```json\n{\n  "code": 0,\n  "data": {\n    "token": "eyJhbGciOi...",\n    "expiresIn": 7200,\n    "isNew": true\n  }\n}\n```\n\n### 后台配置\n\n在后台管理 → 系统配置 → 公众号配置中填写：\n- **公众号 AppID**（weoa_appid）\n- **公众号 AppSecret**（weoa_secret）\n- **公众号 Token**（weoa_token）—— 用于消息验证\n\n### 白名单\n\n`/wm/oa/auth/url` 和 `/wm/oa/auth/callback` 均已加入 MemberAuth 中间件白名单。\n\n## 注册流程\n\n```\n1. 用户填写注册信息（用户名、密码、手机号等）\n2. 前端调用 POST /member/auth/register\n3. 后端校验唯一性（用户名、手机号不重复）\n4. 生成 salt，加密密码\n5. 写入 member 表\n6. 自动登录，返回 Token\n```\n\n## 数据库字段\n\nxy_member 表微信相关字段：\n\n| 字段 | 类型 | 说明 |\n|------|------|------|\n| openid_mapp | varchar(64) | 微信小程序 openid |\n| openid_oa | varchar(64) | 微信公众号 openid |\n| session_key | varchar(128) | 小程序 session_key |\n| wx_avatar | varchar(500) | 微信头像 |\n\n> 小程序和公众号使用独立的 openid，不通过 unionid 打通。同一微信用户在小程序和公众号会注册为两个独立会员。\n\n## 获取用户信息\n\n登录后可通过以下接口获取当前用户信息：\n\n**GET /wm/auth/profile**（需携带 Xy-User-Token）\n\n响应：\n```json\n{\n  "code": 0,\n  "data": {\n    "id": 1,\n    "nickname": "微信用户",\n    "avatar": "",\n    "score": 0,\n    "money": 0,\n    "level": 1\n  }\n}\n```\n\n## 前端使用（UniApp）\n\n```javascript\nimport { useUserStore } from ''@/store/user''\n\nconst store = useUserStore()\n\n// 小程序登录\nconst loginRes = await new Promise((resolve, reject) => {\n  uni.login({ provider: ''weixin'', success: resolve, fail: reject })\n})\nconst data = await wxMappLogin(loginRes.code)\nstore.setToken(data.token)\n\n// 公众号登录（H5）\nconst data = await oaAuthUrl(redirect)\nwindow.location.href = data.url\n\n// 获取用户信息\nawait store.fetchProfile()\n\n// 登出\nstore.logout()\n```\n\n## 路由守卫\n\n会员中心页面需要登录才能访问，在路由守卫中检查：\n- 访问 `/user/*` 路径时检查会员 Token\n- 未登录跳转到 `/user/login`\n- 支持白名单配置（无需登录的页面）',
'XYGo Admin', 0, 90, 1, 0, '["认证","JWT","登录","微信","小程序","公众号"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 会员系统 > 积分与资金 (category_id=503)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(28, 503, '积分与资金', 'score-money', '', '积分日志、资金日志与变动记录管理',
E'# 积分与资金\n\n## 积分系统\n\n### 积分变动场景\n\n| 场景 | 积分变化 | 说明 |\n|------|---------|------|\n| 每日签到 | +N | 签到奖励，连续签到可递增 |\n| 后台调整 | ±N | 管理员手动调整 |\n| 消费扣除 | -N | 积分兑换等场景 |\n\n### 积分日志\n\n每次积分变动都会记录到 `member_score_log` 表：\n\n| 字段 | 说明 |\n|------|------|\n| member_id | 会员 ID |\n| score | 变动积分（正数增加，负数扣除） |\n| balance | 变动后余额 |\n| remark | 变动说明 |\n| created_at | 变动时间 |\n\n### 后台管理\n\n在「会员管理 → 积分日志」中可以：\n- 查看所有会员的积分变动记录\n- 按会员、时间范围筛选\n- 查看积分余额变化趋势\n\n## 资金系统\n\n### 资金变动场景\n\n| 场景 | 资金变化 | 说明 |\n|------|---------|------|\n| 充值 | +N | 会员充值 |\n| 后台调整 | ±N | 管理员手动调整 |\n| 消费 | -N | 购买服务等 |\n\n### 资金日志\n\n记录到 `member_money_log` 表，结构与积分日志类似。\n\n## 前台展示\n\n会员中心中展示积分和余额信息：\n\n```typescript\n// api/frontend/member/score-log.ts\nexport function fetchScoreLog(params: any) {\n  return memberRequest.get({ url: ''/scoreLog/list'', params })\n}\n\n// api/frontend/member/money-log.ts\nexport function fetchMoneyLog(params: any) {\n  return memberRequest.get({ url: ''/moneyLog/list'', params })\n}\n```',
'XYGo Admin', 0, 80, 1, 0, '["积分","资金"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 会员系统 > 签到系统 (category_id=504)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(29, 504, '签到系统', 'checkin', '', '每日签到功能与连续签到奖励',
E'# 签到系统\n\n## 功能说明\n\n会员每日签到可获得积分奖励，连续签到天数越多奖励越高。\n\n## 签到规则\n\n- 每天只能签到一次\n- 签到成功后获得积分奖励\n- 连续签到天数会累计\n- 断签后连续天数重置为 1\n\n## 数据结构\n\n`member_checkin` 表：\n\n| 字段 | 说明 |\n|------|------|\n| member_id | 会员 ID |\n| days | 连续签到天数 |\n| last_checkin_at | 最后签到时间 |\n| total_days | 累计签到总天数 |\n\n## 后端实现\n\n签到逻辑在 `internal/logic/member/checkin.go` 中：\n\n```go\n// 签到流程\n1. 检查今天是否已签到\n2. 判断是否连续签到（昨天是否签到）\n3. 更新连续天数（连续 +1，断签重置为 1）\n4. 计算积分奖励\n5. 增加会员积分 + 记录积分日志\n6. 更新签到记录\n```\n\n## 前端调用\n\n```typescript\n// api/frontend/member/checkin.ts\nimport { memberRequest } from ''@/utils/http''\n\n// 执行签到\nexport function doCheckin() {\n  return memberRequest.post({ url: ''/checkin/sign'' })\n}\n\n// 获取签到状态\nexport function getCheckinStatus() {\n  return memberRequest.get({ url: ''/checkin/status'' })\n}\n```\n\n## 前台展示\n\n会员中心和社区页面中展示签到组件：\n- 显示连续签到天数\n- 7 天签到日历\n- 签到按钮（已签到则置灰）\n- 积分奖励提示',
'XYGo Admin', 0, 70, 1, 0, '["签到","积分"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 安装帮助 > Windows安装 (category_id=601)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(30, 601, 'Windows 安装', 'install-windows', '', 'Windows 环境下从零搭建开发环境',
E'# Windows 安装\n\n## 1. 安装 Go\n\n1. 访问 [Go 官网](https://go.dev/dl/) 下载 Windows 安装包\n2. 运行安装程序，默认安装到 `C:\\Go`\n3. 验证安装：\n\n```powershell\ngo version\n# go1.24.0 windows/amd64\n```\n\n4. 设置 Go 代理（国内加速）：\n\n```powershell\ngo env -w GOPROXY=https://goproxy.cn,direct\ngo env -w GO111MODULE=on\n```\n\n## 2. 安装 GoFrame CLI\n\n```powershell\ngo install github.com/gogf/gf/cmd/gf/v2@latest\ngf version\n```\n\n## 3. 安装 Node.js\n\n1. 访问 [Node.js 官网](https://nodejs.org/) 下载 LTS 版本\n2. 运行安装程序\n3. 安装 pnpm：\n\n```powershell\nnpm install -g pnpm\npnpm --version\n```\n\n## 4. 安装数据库\n\n### PostgreSQL（推荐）\n\n1. 下载 [PostgreSQL](https://www.postgresql.org/download/windows/)\n2. 安装时设置密码（如 `123456`）\n3. 创建数据库：\n\n```sql\nCREATE DATABASE xygoadmin WITH ENCODING ''UTF8'';\n```\n\n### MySQL（可选）\n\n1. 下载 [MySQL](https://dev.mysql.com/downloads/installer/)\n2. 安装并设置 root 密码\n3. 创建数据库：\n\n```sql\nCREATE DATABASE xygoadmin DEFAULT CHARACTER SET utf8mb4;\n```\n\n## 5. 安装 Redis\n\nWindows 下推荐使用 [Memurai](https://www.memurai.com/) 或 WSL2 中的 Redis。\n\n## 6. 启动项目\n\n```powershell\n# 克隆代码\ngit clone https://github.com/your-org/xygoadmin.git\ncd xygoadmin\n\n# 导入数据库\npsql -U postgres -d xygoadmin -f pgsql_install.sql\n\n# 修改配置文件\n# 编辑 server/manifest/config/config.yaml\n\n# 启动后端\ncd server\ngf run main.go\n\n# 新开终端，启动前端\ncd web\npnpm install\npnpm dev\n```',
'XYGo Admin', 0, 100, 1, 0, '["Windows","安装"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 安装帮助 > Linux安装 (category_id=602)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(31, 602, 'Linux 安装', 'install-linux', '', 'Linux 生产环境部署指南',
E'# Linux 安装\n\n以 Ubuntu 22.04 / CentOS 8 为例。\n\n## 1. 安装 Go\n\n```bash\n# 下载\nwget https://go.dev/dl/go1.24.0.linux-amd64.tar.gz\n\n# 解压\nsudo tar -C /usr/local -xzf go1.24.0.linux-amd64.tar.gz\n\n# 配置环境变量\necho ''export PATH=$PATH:/usr/local/go/bin'' >> ~/.bashrc\necho ''export GOPATH=$HOME/go'' >> ~/.bashrc\necho ''export PATH=$PATH:$GOPATH/bin'' >> ~/.bashrc\nsource ~/.bashrc\n\n# 设置代理\ngo env -w GOPROXY=https://goproxy.cn,direct\n\n# 验证\ngo version\n```\n\n## 2. 安装 Node.js\n\n```bash\n# 使用 nvm 安装（推荐）\ncurl -o- https://raw.githubusercontent.com/nvm-sh/nvm/v0.39.0/install.sh | bash\nsource ~/.bashrc\nnvm install 20\nnvm use 20\n\n# 安装 pnpm\nnpm install -g pnpm\n```\n\n## 3. 安装 PostgreSQL\n\n```bash\n# Ubuntu\nsudo apt update\nsudo apt install postgresql postgresql-contrib\nsudo systemctl start postgresql\nsudo systemctl enable postgresql\n\n# 创建数据库\nsudo -u postgres psql\nCREATE DATABASE xygoadmin WITH ENCODING ''UTF8'';\nALTER USER postgres PASSWORD ''123456'';\n\\q\n```\n\n## 4. 安装 Redis\n\n```bash\nsudo apt install redis-server\nsudo systemctl start redis\nsudo systemctl enable redis\n```\n\n## 5. 部署项目\n\n```bash\n# 克隆代码\ngit clone https://github.com/your-org/xygoadmin.git\ncd xygoadmin\n\n# 导入数据库\npsql -U postgres -d xygoadmin -f pgsql_install.sql\n\n# 编译后端\ncd server\ngo build -o xygoadmin main.go\n\n# 构建前端\ncd ../web\npnpm install\npnpm build\n```\n\n## 6. 配置 Nginx\n\n```bash\nsudo apt install nginx\n```\n\n将前端 `dist/` 目录部署到 Nginx，配置反向代理到后端 8000 端口。详见「构建与部署」文档。\n\n## 7. 配置 systemd\n\n```bash\nsudo vim /etc/systemd/system/xygoadmin.service\n```\n\n```ini\n[Unit]\nDescription=XYGo Admin\nAfter=network.target postgresql.service redis.service\n\n[Service]\nType=simple\nUser=www-data\nWorkingDirectory=/var/www/xygoadmin/server\nExecStart=/var/www/xygoadmin/server/xygoadmin\nRestart=always\n\n[Install]\nWantedBy=multi-user.target\n```\n\n```bash\nsudo systemctl daemon-reload\nsudo systemctl start xygoadmin\nsudo systemctl enable xygoadmin\n```',
'XYGo Admin', 0, 90, 1, 0, '["Linux","部署"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 安装帮助 > 数据库配置 (category_id=603)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(32, 603, '数据库配置', 'database-config', '', 'MySQL 与 PostgreSQL 双数据库配置指南',
E'# 数据库配置\n\nXYGo Admin 同时支持 MySQL 和 PostgreSQL，通过配置文件切换。\n\n## 连接配置\n\n编辑 `server/manifest/config/config.yaml`：\n\n### PostgreSQL\n\n```yaml\ndatabase:\n  default:\n    link: \"pgsql:postgres:123456@tcp(127.0.0.1:5432)/xygoadmin\"\n    debug: true\n    prefix: \"xy_\"\n```\n\n### MySQL\n\n```yaml\ndatabase:\n  default:\n    link: \"mysql:root:123456@tcp(127.0.0.1:3306)/xygoadmin?charset=utf8mb4&parseTime=true&loc=Local\"\n    debug: true\n    prefix: \"xy_\"\n```\n\n## 建表脚本\n\n项目提供两套建表脚本：\n\n| 文件 | 数据库 |\n|------|--------|\n| `mysql_install.sql` | MySQL |\n| `pgsql_install.sql` | PostgreSQL |\n\n## CLI 配置\n\n代码生成器也需要配置数据库连接，编辑 `server/hack/config.yaml`：\n\n```yaml\ngfcli:\n  gen:\n    dao:\n      # PostgreSQL\n      link: \"pgsql:postgres:123456@tcp(127.0.0.1:5432)/xygoadmin\"\n      # MySQL\n      # link: \"mysql:root:123456@tcp(127.0.0.1:3306)/xygoadmin\"\n      removePrefix: \"xy_\"\n      jsonCase: \"CamelLower\"\n```\n\n## 方言适配\n\n项目通过 `library/dbdialect/` 包处理两种数据库的差异：\n\n| 差异点 | MySQL | PostgreSQL |\n|--------|-------|------------|\n| 自增主键 | `AUTO_INCREMENT` | `SERIAL` / `BIGSERIAL` |\n| 布尔类型 | `TINYINT(1)` | `BOOLEAN` |\n| JSON 类型 | `JSON` | `JSONB` |\n| 字符串引号 | 反引号 `` ` `` | 双引号 `\"` |\n| 时间戳 | `BIGINT` | `BIGINT` |\n\n代码生成器在创建表和同步字段时会自动适配当前数据库类型。\n\n## 注意事项\n\n1. 两种数据库不能混用，选定后保持一致\n2. 修改数据库类型后需要重新导入对应的建表脚本\n3. `gf gen dao` 会根据 `hack/config.yaml` 中的连接自动识别数据库类型\n4. PostgreSQL 的 `bigint` 在 Go 中映射为 `uint64`（通过 `typeMapping` 配置）',
'XYGo Admin', 0, 80, 1, 0, '["数据库","MySQL","PostgreSQL"]', 1, 1, 1739980800, 1739980800, 0);

-- ========================================
-- 安装帮助 > 常见安装问题 (category_id=604)
-- ========================================
INSERT INTO xy_cms_doc (id, category_id, title, slug, cover, summary, content, author, views, sort, status, is_top, tags, created_by, updated_by, created_at, updated_at, deleted_at) VALUES
(33, 604, '常见安装问题', 'install-faq', '', '安装过程中常见问题的排查与解决',
E'# 常见安装问题\n\n## Go 相关\n\n### Q: `go install` 下载超时\n\n设置 Go 代理：\n\n```bash\ngo env -w GOPROXY=https://goproxy.cn,direct\n```\n\n### Q: `gf` 命令找不到\n\n确认 `$GOPATH/bin` 在 PATH 中：\n\n```bash\n# 查看 GOPATH\ngo env GOPATH\n\n# 添加到 PATH\nexport PATH=$PATH:$(go env GOPATH)/bin\n```\n\n### Q: `gf gen dao` 连接数据库失败\n\n检查 `server/hack/config.yaml` 中的数据库连接配置：\n- 确认数据库服务已启动\n- 确认用户名密码正确\n- 确认数据库已创建\n- PostgreSQL 注意端口是 5432，MySQL 是 3306\n\n## Node.js 相关\n\n### Q: `pnpm install` 失败\n\n```bash\n# 清除缓存\npnpm store prune\n\n# 设置国内镜像\npnpm config set registry https://registry.npmmirror.com\n\n# 重试\npnpm install\n```\n\n### Q: `pnpm build` 内存不足\n\n```bash\n# 增加 Node.js 内存限制\nexport NODE_OPTIONS=\"--max-old-space-size=4096\"\npnpm build\n```\n\n### Q: 前端启动后页面空白\n\n1. 检查浏览器控制台是否有报错\n2. 确认后端服务已启动\n3. 检查 `vite.config.ts` 中的代理配置是否指向正确的后端地址\n4. 清除浏览器缓存和 localStorage\n\n## 数据库相关\n\n### Q: 导入 SQL 报错\n\n- MySQL：确认使用 `mysql_install.sql`\n- PostgreSQL：确认使用 `pgsql_install.sql`\n- 不要混用两种数据库的 SQL 文件\n\n### Q: PostgreSQL 连接报 \"password authentication failed\"\n\n检查 `pg_hba.conf` 文件，确认本地连接认证方式：\n\n```\n# IPv4 local connections:\nhost    all    all    127.0.0.1/32    md5\n```\n\n修改后重启 PostgreSQL。\n\n### Q: Redis 连接失败\n\n```bash\n# 检查 Redis 是否运行\nredis-cli ping\n# 应返回 PONG\n\n# 检查端口\nnetstat -tlnp | grep 6379\n```\n\n## 端口冲突\n\n### Q: 后端 8000 端口被占用\n\n修改 `config.yaml` 中的端口：\n\n```yaml\nserver:\n  address: \":8001\"\n```\n\n同时修改前端 `vite.config.ts` 中的代理目标地址。\n\n### Q: 前端 5173 端口被占用\n\nVite 会自动尝试下一个可用端口，或手动指定：\n\n```typescript\n// vite.config.ts\nserver: {\n  port: 3000\n}\n```',
'XYGo Admin', 0, 70, 1, 0, '["安装","问题","排查"]', 1, 1, 1739980800, 1739980800, 0);

